    ('o-rain-come', 8, $$“Maya! It’s raining!” Lilato yelled. “It’s raining!” They ran outside the house.$$, $$[{"role": "BODY", "text": "“Maya! It’s raining!” Lilato yelled. “It’s raining!” They ran outside the house.", "bbox": [56.7, 262.1, 497.0, 320.1], "size": 26.0}]$$),
