    ('thats-not-thabi-thats-a-hippopotamus', 0, $$Lucy woke up. Her sister Thabi wasn’t in her bed.$$, $$[{"role": "BODY", "text": "Lucy woke up. Her sister Thabi wasn’t in her bed.", "bbox": [718.6, 428.8, 1039.4, 494.8], "size": 30.0}]$$),
    ('thats-not-thabi-thats-a-hippopotamus', 1, $$“Thabi’s in the kitchen eating breakfast.” “Where’s Thabi?” Lucy asked Ma.$$, $$[{"role": "BODY", "text": "“Thabi’s in the kitchen eating breakfast.”", "bbox": [637.8, 75.0, 823.6, 177.0], "size": 30.0}, {"role": "BODY", "text": "“Where’s Thabi?” Lucy asked Ma.", "bbox": [60.5, 474.9, 491.0, 504.9], "size": 30.0}]$$),
