    ('thats-not-thabi-thats-a-hippopotamus', 6, $$Lucy kept looking around the garden.$$, $$[{"role": "BODY", "text": "Lucy kept looking around the garden.", "bbox": [733.2, 190.7, 981.7, 256.7], "size": 30.0}]$$),
