    ('thats-not-thabi-thats-a-hippopotamus', 8, $$“That’s not Thabi! That’s a hippopotamus!”$$, $$[{"role": "BODY", "text": "“That’s not Thabi!", "bbox": [168.8, 126.4, 398.1, 156.4], "size": 30.0}, {"role": "BODY", "text": "That’s a hippopotamus!”", "bbox": [708.6, 394.8, 1024.5, 424.8], "size": 30.0}]$$),
    ('thats-not-thabi-thats-a-hippopotamus', 9, $$Then Lucy heard a funny noise. She gave the hippopotamus a big tickle.$$, $$[{"role": "BODY", "text": "Then Lucy heard a funny noise. She gave the hippopotamus a big tickle.", "bbox": [138.9, 193.5, 423.6, 331.5], "size": 30.0}]$$),
