    ('the-best-nest', 0, $$Blue Bird is bored. “I am tired of this nest,” he says. “We need a new home.”$$, $$[{"role": "BODY", "text": "Blue Bird is bored. “I am tired of this nest,” he says.", "bbox": [99.6, 147.2, 467.3, 186.8], "size": 18.0}, {"role": "BODY", "text": "“We need a new home.”", "bbox": [180.6, 212.0, 386.4, 230.0], "size": 18.0}]$$),
    ('the-best-nest', 1, $$“If you insist,” says Brown Bird. “But I am not moving unless the new nest is better than the one that we have now.” “Oh yes,” says Blue Bird. “It will be a great nest. I will find the best nest ever!”$$, $$[{"role": "BODY", "text": "“If you insist,” says Brown Bird.", "bbox": [212.0, 111.8, 354.9, 151.3], "size": 18.0}, {"role": "BODY", "text": "“But I am not moving unless the new nest is better than the one that we have now.”", "bbox": [95.2, 198.2, 471.7, 237.8], "size": 18.0}, {"role": "BODY", "text": "“Oh yes,” says Blue Bird.", "bbox": [220.7, 262.9, 346.3, 302.6], "size": 18.0}, {"role": "BODY", "text": "“It will be a great nest. I will find the best nest ever!”", "bbox": [157.7, 327.8, 409.2, 367.4], "size": 18.0}]$$),
    ('the-best-nest', 2, $$“Look at this lovely nest! It is soft and cosy. And we can each have our own bed. This is the best nest for us.”$$, $$[{"role": "BODY", "text": "“Look at this lovely nest! It is soft and cosy. And we can each have our own bed.", "bbox": [680.9, 63.4, 1056.7, 103.0], "size": 18.0}, {"role": "BODY", "text": "This is the best nest for us.”", "bbox": [749.1, 128.2, 988.5, 146.2], "size": 18.0}]$$),
    ('the-best-nest', 3, $$But it isn’t!$$, $$[{"role": "SFX", "text": "But it isn’t!", "bbox": [209.2, 65.5, 357.7, 94.5], "size": 29.0}]$$),
    ('the-best-nest', 4, $$“Look at this beautiful nest. It is so bright and colourful. This is the very best nest.”$$, $$[{"role": "BODY", "text": "“Look at this beautiful nest. It is so bright and colourful.", "bbox": [609.1, 62.1, 1091.7, 80.2], "size": 18.0}, {"role": "BODY", "text": "This is the very best nest.”", "bbox": [736.6, 105.3, 964.2, 123.3], "size": 18.0}]$$),
    ('the-best-nest', 5, $$But it isn’t!$$, $$[{"role": "SFX", "text": "But it isn’t!", "bbox": [350.9, 271.0, 499.4, 300.0], "size": 29.0}]$$),
    ('the-best-nest', 6, $$“Look at this shiny nest. See how it sparkles. This is the best nest yet.”$$, $$[{"role": "BODY", "text": "“Look at this shiny nest. See how it sparkles.", "bbox": [659.0, 95.8, 1041.8, 113.8], "size": 18.0}, {"role": "BODY", "text": "This is the best nest yet.”", "bbox": [741.9, 138.9, 958.9, 156.9], "size": 18.0}]$$),
    ('the-best-nest', 7, $$But it isn’t!$$, $$[{"role": "SFX", "text": "But it isn’t!", "bbox": [334.6, 65.5, 483.1, 94.5], "size": 29.0}]$$),
    ('the-best-nest', 8, $$“Look at this large nest! It even has its own door. This is the best nest of all.”$$, $$[{"role": "BODY", "text": "“Look at this large nest! It even has its own door.", "bbox": [712.2, 62.1, 921.5, 101.8], "size": 18.0}, {"role": "BODY", "text": "This is the best nest of all.”", "bbox": [700.2, 127.0, 933.5, 144.9], "size": 18.0}]$$),
    ('the-best-nest', 9, $$But it isn’t!$$, $$[{"role": "SFX", "text": "But it isn’t!", "bbox": [662.8, 380.1, 811.3, 409.1], "size": 29.0}]$$),
    ('the-best-nest', 10, $$“Look at this nest. See how well it has been built. This is the best nest ever.”$$, $$[{"role": "BODY", "text": "“Look at this nest. See how well it has been built.", "bbox": [691.6, 62.1, 950.4, 101.8], "size": 18.0}, {"role": "BODY", "text": "This is the best nest ever.”", "bbox": [708.4, 127.0, 933.6, 144.9], "size": 18.0}]$$),
    ('the-best-nest', 11, $$“Yes, it is,” says Brown Bird.$$, $$[{"role": "BODY", "text": "“Yes, it is,” says Brown Bird.", "bbox": [668.4, 154.3, 828.4, 203.6], "size": 25.0}]$$),
    ('the-best-nest', 12, $$$$, $$[]$$),
    ('the-best-nest', 13, $$$$, $$[]$$),
    ('the-biscuit-jar-must-fall', 0, $$Micki and her friends Lolo and Unathi were reading their favourite books. “If you help Micki clean her room,” Prudence said, “you can all have biscuits afterwards.” “YAY!”$$, $$[{"role": "BODY", "text": "Micki and her friends Lolo and Unathi were reading their favourite books.", "bbox": [623.6, 76.2, 1056.0, 131.2], "size": 25.0}, {"role": "BODY", "text": "“If you help Micki clean her room,” Prudence said, “you can all have biscuits afterwards.”", "bbox": [623.6, 166.2, 1028.3, 251.2], "size": 25.0}, {"role": "BODY", "text": "“YAY!”", "bbox": [623.6, 286.2, 707.4, 311.2], "size": 25.0}]$$),
    ('the-biscuit-jar-must-fall', 1, $$But they carried on and read and read and read.$$, $$[{"role": "BODY", "text": "But they carried on and read and read and read.", "bbox": [56.7, 272.8, 498.2, 327.8], "size": 25.0}]$$),
    ('the-biscuit-jar-must-fall', 2, $$Then they stopped reading and cleaned Micki’s room.$$, $$[{"role": "BODY", "text": "Then they stopped reading and cleaned Micki’s room.", "bbox": [56.7, 272.8, 510.3, 327.8], "size": 25.0}]$$),
    ('the-biscuit-jar-must-fall', 3, $$“My room is tidy now,” Micki said. “Let’s go and get biscuits.” But they could not find Prudence anywhere.$$, $$[{"role": "BODY", "text": "“My room is tidy now,” Micki said. “Let’s go and get biscuits.”", "bbox": [623.6, 132.9, 1017.6, 187.9], "size": 25.0}, {"role": "BODY", "text": "But they could not find Prudence anywhere.", "bbox": [623.6, 222.9, 1001.3, 277.9], "size": 25.0}]$$),
    ('the-biscuit-jar-must-fall', 4, $$Micki, Lolo and Unathi stared at the biscuit jar on the top shelf wondering how to reach it.$$, $$[{"role": "BODY", "text": "Micki, Lolo and Unathi stared at the biscuit jar on the top shelf wondering how to reach it.", "bbox": [56.7, 439.3, 426.6, 524.3], "size": 25.0}]$$),
    ('the-biscuit-jar-must-fall', 5, $$So they found a chair and took turns to climb on it. But none of them could reach the biscuit jar. “My mama would say this is dangerous and we could fall and hurt ourselves,” Lolo said.$$, $$[{"role": "BODY", "text": "So they found a chair and took turns to climb on it.", "bbox": [56.7, 259.3, 409.1, 314.3], "size": 25.0}, {"role": "BODY", "text": "But none of them could reach the biscuit jar.", "bbox": [56.7, 349.3, 395.9, 404.3], "size": 25.0}, {"role": "BODY", "text": "“My mama would say this is dangerous and we could fall and hurt ourselves,” Lolo said.", "bbox": [56.7, 439.3, 409.3, 524.3], "size": 25.0}]$$),
    ('the-biscuit-jar-must-fall', 6, $$So Lolo sat on Unathi’s shoulders and stretched out his arms but could not reach the biscuit jar. “My father would say this is dangerous and we could fall and hurt ourselves,” Unathi said.$$, $$[{"role": "BODY", "text": "So Lolo sat on Unathi’s shoulders and stretched out his arms but could not reach the biscuit jar.", "bbox": [56.7, 320.0, 488.7, 405.0], "size": 25.0}, {"role": "BODY", "text": "“My father would say this is dangerous and we could fall and hurt ourselves,” Unathi said.", "bbox": [56.7, 440.0, 507.3, 525.0], "size": 25.0}]$$),
    ('the-biscuit-jar-must-fall', 7, $$So they found a rope to throw around the biscuit jar and pull it down. But they could still not reach the biscuit jar. “My mummy would say this is dangerous and the jar could fall on us and hurt us,” Micki said.$$, $$[{"role": "BODY", "text": "So they found a rope to throw around the biscuit jar and pull it down.", "bbox": [56.7, 76.2, 490.7, 131.2], "size": 25.0}, {"role": "BODY", "text": "But they could still not reach the biscuit jar.", "bbox": [56.7, 166.2, 434.8, 221.2], "size": 25.0}, {"role": "BODY", "text": "“My mummy would say this is dangerous and the jar could fall on us and hurt us,” Micki said.", "bbox": [56.7, 256.2, 492.1, 341.2], "size": 25.0}]$$),
    ('the-biscuit-jar-must-fall', 8, $$“What are you doing?” Jonathan and Sakhi asked. “We are trying to reach the biscuit jar,” Micki said. “We can help you,” they said.$$, $$[{"role": "BODY", "text": "“What are you doing?” Jonathan and Sakhi asked.", "bbox": [56.7, 379.3, 370.4, 434.3], "size": 25.0}, {"role": "BODY", "text": "“We are trying to reach the biscuit jar,” Micki said.", "bbox": [56.7, 469.3, 460.0, 524.3], "size": 25.0}, {"role": "BODY", "text": "“We can help you,” they said.", "bbox": [623.6, 469.1, 853.6, 524.1], "size": 25.0}]$$),
    ('the-biscuit-jar-must-fall', 9, $$“Let’s push the table close to the shelf and climb on that instead,” Jonathan said. But still, none of them could reach the biscuit jar.$$, $$[{"role": "BODY", "text": "“Let’s push the table close to the shelf and climb on that instead,” Jonathan said.", "bbox": [731.3, 277.5, 1066.9, 362.5], "size": 25.0}, {"role": "BODY", "text": "But still, none of them could reach the biscuit jar.", "bbox": [731.3, 397.5, 1056.0, 452.5], "size": 25.0}]$$),
    ('the-biscuit-jar-must-fall', 10, $$“Let’s throw a ball at the jar and knock it down so that the biscuits fall out,” Sakhi said. “Yes!” Lolo and Jonathan said. “No!” Unathi and Micki said.$$, $$[{"role": "BODY", "text": "“Let’s throw a ball at the jar and knock it down so that the biscuits fall out,” Sakhi said.", "bbox": [56.7, 348.4, 506.3, 433.4], "size": 25.0}, {"role": "BODY", "text": "“Yes!” Lolo and Jonathan said. “No!” Unathi and Micki said.", "bbox": [56.7, 468.4, 412.7, 523.4], "size": 25.0}]$$),
    ('the-biscuit-jar-must-fall', 11, $$Finally, Micki had an idea… And that is how, together, they reached the biscuit jar!$$, $$[{"role": "BODY", "text": "Finally, Micki had an idea…", "bbox": [163.7, 499.3, 476.9, 524.3], "size": 25.0}, {"role": "BODY", "text": "And that is how, together, they reached the biscuit jar!", "bbox": [909.2, 269.7, 1079.0, 384.7], "size": 25.0}]$$),
    ('the-biscuit-jar-must-fall', 12, $$$$, $$[]$$),
    ('the-biscuit-jar-must-fall', 13, $$$$, $$[]$$),
    ('the-bounce', 0, $$In a little yellow house lived a big black dog. The big black dog loved to bounce.$$, $$[{"role": "BODY", "text": "In a little yellow house lived a big black dog.", "bbox": [99.4, 84.2, 467.6, 104.2], "size": 20.0}, {"role": "BODY", "text": "The big black dog loved to bounce.", "bbox": [704.2, 84.2, 996.6, 104.2], "size": 20.0}]$$),
    ('the-bounce', 1, $$He had everything he could ever need, but Black Dog was unhappy. His human worked most of the day, so they could only play late in the afternoon.$$, $$[{"role": "BODY", "text": "He had everything he could ever need, but Black Dog was unhappy.", "bbox": [122.1, 190.5, 444.9, 240.5], "size": 20.0}, {"role": "BODY", "text": "His human worked most of the day, so they could only play late in the afternoon.", "bbox": [136.2, 280.5, 430.7, 360.5], "size": 20.0}]$$),
    ('the-bounce', 2, $$In the big house next door lived a little girl and her two spotty dogs. One morning when Black Dog’s human left for work, he heard the little girl laughing. “It would be fun to have someone to play with,” Black Dog sighed. So, he started to bounce. He bounced . . . and bounced . . . and bounced . . .$$, $$[{"role": "BODY", "text": "In the big house next door lived a little girl and her two spotty dogs.", "bbox": [107.7, 89.8, 459.3, 139.8], "size": 20.0}, {"role": "BODY", "text": "One morning when Black Dog’s human left for work, he heard the little girl laughing.", "bbox": [67.3, 179.8, 499.6, 229.8], "size": 20.0}, {"role": "BODY", "text": "“It would be fun to have someone to play with,” Black Dog sighed.", "bbox": [87.7, 269.8, 479.2, 319.8], "size": 20.0}, {"role": "BODY", "text": "So, he started to bounce.", "bbox": [179.0, 359.8, 387.9, 379.8], "size": 20.0}, {"role": "BODY", "text": "He bounced . . . and bounced . . . and bounced . . .", "bbox": [214.6, 419.8, 352.4, 499.8], "size": 20.0}]$$),
    ('the-bounce', 3, $$. . . until he bounced so high that he landed in the little girl’s garden. At first Black Dog had loads of fun.$$, $$[{"role": "BODY", "text": ". . . until he bounced so high that he landed in the little girl’s garden.", "bbox": [103.6, 84.2, 463.4, 134.2], "size": 20.0}, {"role": "BODY", "text": "At first Black Dog had loads of fun.", "bbox": [706.9, 84.2, 993.9, 104.2], "size": 20.0}]$$),
    ('the-bounce', 4, $$But then the little girl started pulling tails and twisting ears. “This is no fun!” Black Dog yelped. So he started to bounce. He bounced . . . and bounced . . . and bounced . . .$$, $$[{"role": "BODY", "text": "But then the little girl started pulling tails and twisting ears.", "bbox": [701.2, 108.3, 999.6, 158.3], "size": 20.0}, {"role": "BODY", "text": "“This is no fun!” Black Dog yelped.", "bbox": [706.2, 198.3, 994.6, 218.3], "size": 20.0}, {"role": "BODY", "text": "So he started to bounce. He bounced . . . and bounced . . . and bounced . . .", "bbox": [748.0, 258.3, 952.8, 368.3], "size": 20.0}]$$),
    ('the-bounce', 5, $$. . . until he bounced so high that he landed back in his own garden. In the big house on the other side lived an old lady with a little yellow dog. “I’m sure she won’t pull my tail or twist my ears. It would be great to play with her,” sighed Black Dog.$$, $$[{"role": "BODY", "text": ". . . until he bounced so high that he landed back in his own garden. In the big house on the other side lived an old lady with a little yellow dog.", "bbox": [123.0, 67.2, 443.9, 177.2], "size": 20.0}, {"role": "BODY", "text": "“I’m sure she won’t pull my tail or twist my ears. It would be great to play with her,” sighed Black Dog.", "bbox": [124.7, 217.2, 442.2, 297.2], "size": 20.0}]$$),
    ('the-bounce', 6, $$So he started to bounce. He bounced . . . and bounced . . . and bounced . . . . . . until he bounced so high that he landed in the old lady’s garden.$$, $$[{"role": "BODY", "text": "So he started to bounce.", "bbox": [748.0, 119.7, 952.8, 139.7], "size": 20.0}, {"role": "BODY", "text": "He bounced . . . and bounced . . . and bounced . . .", "bbox": [781.5, 179.7, 919.3, 259.6], "size": 20.0}, {"role": "BODY", "text": ". . . until he bounced so high that he landed in the old lady’s garden.", "bbox": [702.2, 299.6, 998.6, 349.6], "size": 20.0}]$$),
    ('the-bounce', 7, $$At first, the lady scratched Black Dog behind his ears and rubbed his tummy. But after a while, the old lady sat down in her rocking chair and Black Dog got really bored. Yaaaaaawn...$$, $$[{"role": "BODY", "text": "At first, the lady scratched Black Dog behind his ears and rubbed his tummy. But after a while, the old lady sat down in her rocking chair and Black Dog got really bored.", "bbox": [75.3, 182.0, 491.6, 292.0], "size": 20.0}, {"role": "SFX", "text": "Yaaaaaawn...", "bbox": [717.1, 356.6, 947.0, 427.7], "size": 43.6}]$$),
    ('the-bounce', 8, $$So he started to bounce. He bounced . . . and bounced . . . and bounced . . .$$, $$[{"role": "BODY", "text": "So he started to bounce.", "bbox": [748.0, 111.8, 952.8, 131.8], "size": 20.0}, {"role": "BODY", "text": "He bounced . . . and bounced . . . and bounced . . .", "bbox": [781.5, 171.8, 919.3, 251.8], "size": 20.0}]$$),
    ('the-bounce', 9, $$. . . until he bounced so high that he landed in his own garden again. When Black Dog’s human came home she didn’t pull his tail or sit in a chair scratching his ears.$$, $$[{"role": "BODY", "text": ". . . until he bounced so high that he landed in his own garden again.", "bbox": [176.4, 142.3, 472.8, 192.3], "size": 20.0}, {"role": "BODY", "text": "When Black Dog’s human came home she didn’t pull his tail or sit in a chair scratching his ears.", "bbox": [166.2, 232.3, 482.9, 312.3], "size": 20.0}]$$),
    ('the-bounce', 10, $$They played his favourite game and she told him how much she’d missed him all day long.$$, $$[{"role": "BODY", "text": "They played his favourite game and she told him how much she’d missed him all day long.", "bbox": [703.6, 240.1, 1011.4, 320.1], "size": 20.0}]$$),
    ('the-bounce', 11, $$“I love her and she loves me. I am a lucky dog after all!” Black Dog sighed happily, as they curled up on the couch together.$$, $$[{"role": "BODY", "text": "“I love her and she loves me. I am a lucky dog after all!” Black Dog sighed happily, as they curled up on the couch together.", "bbox": [52.2, 111.8, 514.8, 191.8], "size": 20.0}]$$),
    ('the-bounce', 12, $$$$, $$[]$$),
    ('the-bounce', 13, $$$$, $$[]$$),
    ('the-box', 0, $$Andi is bored. Max is bored, too.$$, $$[{"role": "BODY", "text": "Andi is bored.", "bbox": [384.2, 61.1, 510.2, 81.1], "size": 20.0}, {"role": "BODY", "text": "Max is bored, too.", "bbox": [912.4, 61.1, 1077.2, 81.1], "size": 20.0}]$$),
    ('the-box', 1, $$“What’s in the box, Dad?”$$, $$[{"role": "BODY", "text": "“What’s in the box, Dad?”", "bbox": [275.1, 61.1, 510.2, 81.1], "size": 20.0}]$$),
    ('the-box', 2, $$It’s only fruit and vegetables.$$, $$[{"role": "BODY", "text": "It’s only fruit and vegetables.", "bbox": [56.7, 61.1, 205.6, 106.1], "size": 20.0}]$$),
    ('the-box', 3, $$“Do you want to play with it?”$$, $$[{"role": "BODY", "text": "“Do you want to play with it?”", "bbox": [347.2, 270.4, 491.7, 315.4], "size": 20.0}]$$),
    ('the-box', 4, $$“What will we do with the box?”$$, $$[{"role": "BODY", "text": "“What will we do with the box?”", "bbox": [56.7, 61.1, 348.2, 81.1], "size": 20.0}]$$),
    ('the-box', 5, $$Asanda comes to play. “Wow! What a cool box!”$$, $$[{"role": "BODY", "text": "Asanda comes to play. “Wow! What a cool box!”", "bbox": [56.7, 61.1, 504.3, 81.1], "size": 20.0}]$$),
    ('the-box', 6, $$WHOOOOSH$$, $$[{"role": "SFX", "text": "WHOOOOSH", "bbox": [819.0, 287.8, 1110.5, 552.9], "size": 67.0}]$$),
    ('the-box', 7, $$Paul comes to play. “Wow! What a cool box!”$$, $$[{"role": "BODY", "text": "Paul comes to play. “Wow! What a cool box!”", "bbox": [56.7, 61.1, 473.6, 81.1], "size": 20.0}]$$),
    ('the-box', 8, $$RAHHHRRR$$, $$[{"role": "SFX", "text": "RAHHHRRR", "bbox": [231.2, 202.4, 495.7, 324.6], "size": 80.0}]$$),
    ('the-box', 9, $$Niki comes to play. “Wow! What a cool box!”$$, $$[{"role": "BODY", "text": "Niki comes to play. “Wow! What a cool box!”", "bbox": [56.7, 61.1, 467.6, 81.1], "size": 20.0}]$$),
    ('the-box', 10, $$WHEEEEE$$, $$[{"role": "SFX", "text": "WHEEEEE", "bbox": [321.1, 82.3, 527.3, 335.8], "size": 62.4}]$$),
