    ('the-boy-who-only-ate-pancakes', 0, $$Rekai loved to eat pancakes more than anything in the whole world.$$, $$[{"role": "BODY", "text": "Rekai loved to eat pancakes more than anything in the whole world.", "bbox": [156.7, 221.9, 410.2, 367.9], "size": 26.0}]$$),
    ('the-boy-who-only-ate-pancakes', 1, $$He loved pancakes so very much. He simply refused to eat any other food!$$, $$[{"role": "BODY", "text": "He loved pancakes so very much. He simply refused to eat any other food!", "bbox": [149.9, 221.5, 417.0, 367.5], "size": 26.0}]$$),
    ('the-boy-who-only-ate-pancakes', 2, $$Rekai’s mom said, “Eat some good food . Have some veggies and fruit! And don’t forget water and juice.”$$, $$[{"role": "BODY", "text": "Rekai’s mom said, “Eat some good food . Have some veggies and fruit! And don’t forget water and juice.”", "bbox": [635.8, 210.0, 898.5, 456.0], "size": 26.0}]$$),
    ('the-boy-who-only-ate-pancakes', 3, $$But Rekai shook his head and said , “NO! I don’t want to. Only pancakes will do!”$$, $$[{"role": "BODY", "text": "But Rekai shook his head and said , “NO! I don’t want to. Only pancakes will do!”", "bbox": [682.9, 206.5, 1017.9, 391.8], "size": 26.0}]$$),
    ('the-boy-who-only-ate-pancakes', 4, $$Then his mom had an idea . “I know how to get Rekai to eat healthy food!” she said.$$, $$[{"role": "BODY", "text": "Then his mom had an idea . “I know how to get Rekai to eat healthy food!” she said.", "bbox": [699.0, 216.5, 1001.8, 372.5], "size": 29.0}]$$),
    ('the-boy-who-only-ate-pancakes', 5, $$She mixed up a batch of some extra special pancakes with a surprise ingredient.$$, $$[{"role": "BODY", "text": "She mixed up a batch of some extra special pancakes with a surprise ingredient.", "bbox": [137.3, 186.5, 428.7, 402.5], "size": 32.0}]$$),
    ('the-boy-who-only-ate-pancakes', 6, $$Mom watched as he gobbled them up, and she was very pleased.$$, $$[{"role": "BODY", "text": "Mom watched as he gobbled them up, and she was very pleased.", "bbox": [141.8, 209.0, 413.8, 363.0], "size": 27.5}]$$),
    ('the-boy-who-only-ate-pancakes', 7, $$Softly, she giggled and thought, this is great . He has no clue what he has just eaten!$$, $$[{"role": "BODY", "text": "Softly, she giggled and thought, this is great . He has no clue what he has just eaten!", "bbox": [131.6, 185.4, 391.9, 390.4], "size": 27.5}]$$),
    ('the-boy-who-only-ate-pancakes', 8, $$Then, one day, Rekai caught Mom adding butternut to his pancakes and he was very surprised. “Your secret ingredient is a vegetable?” he cried.$$, $$[{"role": "BODY", "text": "Then, one day, Rekai caught Mom adding butternut to his pancakes and he was very surprised. “Your secret ingredient is a vegetable?” he cried.", "bbox": [631.5, 68.6, 916.3, 380.6], "size": 32.0}]$$),
    ('the-boy-who-only-ate-pancakes', 9, $$To this day he enjoys eating his pancakes, and every day Mom adds many yummy surprises.$$, $$[{"role": "BODY", "text": "To this day he enjoys eating his pancakes, and every day Mom adds many yummy surprises.", "bbox": [754.7, 87.5, 1012.3, 273.5], "size": 26.0}]$$),
    ('the-boy-who-only-ate-pancakes', 10, $$Sometimes she adds spinach. Sometimes she adds carrots. Sometimes she adds strawberries, or even apples.$$, $$[{"role": "BODY", "text": "Sometimes she adds spinach. Sometimes she adds carrots. Sometimes she adds strawberries, or even apples.", "bbox": [71.9, 201.5, 386.4, 387.5], "size": 26.0}]$$),
    ('the-boy-who-only-ate-pancakes', 11, $$It’s a fun surprise every single time.$$, $$[{"role": "BODY", "text": "It’s a fun surprise every single time.", "bbox": [56.7, 68.6, 272.0, 246.4], "size": 43.5}]$$),
    ('the-boy-who-only-ate-pancakes', 12, $$Pancake surprise recipe 1 cup (250ml) self-raising flour 1 egg 1 cup (250ml) of milk 1 tbsp (15ml) sugar 2 tbsp (30ml) melted butter or margarine A pinch of salt 1 tsp (5ml) cooking oil Surprise: A handful of boiled and drained veggies or mashed fruit of your choice. Method: Separate the egg and whisk egg white separately until it has soft peaks, and set aside. Mix egg yolk with sugar, milk, salt and butter. Add all the wet ingredients to the self-raising flour and mix thoroughly. Mix in pre-boiled veg or mashed fruit, then finally, the egg whites. Add the desired amount of batter to a pan on medium heat and turn once bubbly and golden brown. Enjoy!$$, $$[{"role": "BODY", "text": "Pancake surprise recipe", "bbox": [56.7, 56.9, 381.9, 84.9], "size": 28.0}, {"role": "BODY", "text": "1 cup (250ml) self-raising flour 1 egg 1 cup (250ml) of milk 1 tbsp (15ml) sugar 2 tbsp (30ml) melted butter or margarine A pinch of salt 1 tsp (5ml) cooking oil Surprise: A handful of boiled and drained veggies or mashed fruit of your choice.", "bbox": [56.7, 110.6, 344.6, 290.6], "size": 12.0}, {"role": "SFX", "text": "Method: Separate the egg and whisk egg white separately until it has soft peaks, and set aside. Mix egg yolk with sugar, milk, salt and butter. Add all the wet ingredients to the self-raising flour and mix thoroughly. Mix in pre-boiled veg or mashed fruit, then finally, the egg whites. Add the desired amount of batter to a pan on medium heat and turn once bubbly and golden brown. Enjoy!", "bbox": [56.7, 308.8, 476.9, 506.0], "size": 15.0}]$$),
    ('the-boy-who-only-ate-pancakes', 13, $$$$, $$[]$$),
    ('the-cottonwool-doctor', 0, $$Once upon a time, about 200 years ago, there was a girl called Margaret Ann Bulkly. Margaret lived in a cool, green land called Ireland, in a country called Great Britain. Margaret was clever and curious. Margaret had big dreams. Margaret was brave and fought when she thought something was wrong.$$, $$[{"role": "BODY", "text": "Once upon a time, about 200 years ago, there was a girl called Margaret Ann Bulkly. Margaret lived in a cool, green land called Ireland, in a country called Great Britain.", "bbox": [63.4, 202.6, 503.5, 302.6], "size": 22.0}, {"role": "BODY", "text": "Margaret was clever and curious. Margaret had big dreams. Margaret was brave and fought when she thought something was wrong.", "bbox": [59.8, 332.6, 507.1, 406.6], "size": 22.0}]$$),
    ('the-cottonwool-doctor', 1, $$Margaret’s mother and father paid for her brother to be educated as a lawyer. And then they used the last of their money so that he could marry a wealthy man’s daughter. Margaret was clever and had big dreams. But there was no money left for her to study, not even as a governess or a nurse. Margaret was brave. “I want to be a doctor!” she said. But two hundred years ago a girl could not become a lawyer or a politician or a doctor.$$, $$[{"role": "BODY", "text": "Margaret’s mother and father paid for her brother to be educated as a lawyer. And then they used the last of their money so that he could marry a wealthy man’s daughter.", "bbox": [63.7, 150.6, 503.2, 250.6], "size": 22.0}, {"role": "BODY", "text": "Margaret was clever and had big dreams. But there was no money left for her to study, not even as a governess or a nurse.", "bbox": [59.9, 280.6, 507.0, 354.6], "size": 22.0}, {"role": "BODY", "text": "Margaret was brave. “I want to be a doctor!” she said. But two hundred years ago a girl could not become a lawyer or a politician or a doctor.", "bbox": [70.8, 384.6, 496.1, 458.6], "size": 22.0}]$$),
    ('the-cottonwool-doctor', 2, $$Margaret had an uncle who was a famous painter. His name was James Barry. One of James Barry’s friends was General Miranda from Venezuela. General Miranda had a library – it was very beautiful and very big. His library had more than 6000 books! “I want to read this one! And this one! And this one!” said Margaret. Margaret was clever and curious. General Miranda was impressed.$$, $$[{"role": "BODY", "text": "Margaret had an uncle who was a famous painter. His name was James Barry.", "bbox": [64.5, 163.6, 502.4, 211.6], "size": 22.0}, {"role": "BODY", "text": "One of James Barry’s friends was General Miranda from Venezuela. General Miranda had a library – it was very beautiful and very big. His library had more than 6000 books!", "bbox": [60.8, 241.6, 506.2, 341.6], "size": 22.0}, {"role": "BODY", "text": "“I want to read this one! And this one! And this one!” said Margaret. Margaret was clever and curious. General Miranda was impressed.", "bbox": [74.7, 371.6, 492.3, 445.6], "size": 22.0}]$$),
    ('the-cottonwool-doctor', 3, $$When Margaret’s uncle James Barry died, he left her some money. “It’s enough money to study to be a doctor!” said General Miranda. “But I can’t become a doctor,” said Margaret. “A boy can become a doctor,” said General Miranda. “And you can dress like a boy.” Margaret was brave and she fought for what she believed in. She really wanted to be a doctor. So she cut off her hair. She practiced speaking in a deep voice. She put on boy’s clothes. From then onwards, no one knew that Margaret was a girl. She became James Barry, just like her uncle.$$, $$[{"role": "BODY", "text": "When Margaret’s uncle James Barry died, he left her some money. “It’s enough money to study to be a doctor!” said General Miranda.", "bbox": [54.4, 111.6, 512.5, 185.6], "size": 22.0}, {"role": "BODY", "text": "“But I can’t become a doctor,” said Margaret. “A boy can become a doctor,” said General Miranda. “And you can dress like a boy.”", "bbox": [54.8, 215.6, 512.1, 289.6], "size": 22.0}, {"role": "BODY", "text": "Margaret was brave and she fought for what she believed in. She really wanted to be a doctor. So she cut off her hair. She practiced speaking in a deep voice. She put on boy’s clothes.", "bbox": [61.4, 319.6, 505.6, 419.6], "size": 22.0}, {"role": "BODY", "text": "From then onwards, no one knew that Margaret was a girl. She became James Barry, just like her uncle.", "bbox": [52.0, 449.6, 514.9, 497.6], "size": 22.0}]$$),
    ('the-cottonwool-doctor', 4, $$James Barry was a hard-working medical student. He took 13 subjects and worked all through the summer when the other students went on holiday. But after five years, he nearly didn’t get to write his final exam. The examiners thought he looked too young! James Barry didn’t have a beard because he wasn’t a man.$$, $$[{"role": "BODY", "text": "James Barry was a hard-working medical student. He took 13 subjects and worked all through the summer when the other students went on holiday.", "bbox": [63.5, 202.6, 503.4, 276.6], "size": 22.0}, {"role": "BODY", "text": "But after five years, he nearly didn’t get to write his final exam. The examiners thought he looked too young! James Barry didn’t have a beard because he wasn’t a man.", "bbox": [57.3, 306.6, 509.7, 406.6], "size": 22.0}]$$),
    ('the-cottonwool-doctor', 5, $$Dr James Barry was brave and curious. Dr James Barry had big dreams. So he joined the army. In the army you would see the world! In 1816, the army sent Dr James Barry to Cape Town. Cape Town was a small, interesting city in South Africa. South Africa was far, far away from Ireland. Dr James Barry felt excited.$$, $$[{"role": "BODY", "text": "Dr James Barry was brave and curious. Dr James Barry had big dreams. So he joined the army. In the army you would see the world!", "bbox": [70.3, 176.6, 496.6, 250.6], "size": 22.0}, {"role": "BODY", "text": "In 1816, the army sent Dr James Barry to Cape Town. Cape Town was a small, interesting city in South Africa. South Africa was far, far away from Ireland.", "bbox": [74.8, 280.6, 492.1, 380.6], "size": 22.0}, {"role": "BODY", "text": "Dr James Barry felt excited.", "bbox": [163.2, 410.6, 403.7, 432.6], "size": 22.0}]$$),
    ('the-cottonwool-doctor', 6, $$Dr James Barry was short and slim. He wore platform shoes to look taller and padding under his clothes to look bigger. The people of Cape Town called Dr James Barry the kapok dokter, the cottonwool doctor.$$, $$[{"role": "BODY", "text": "Dr James Barry was short and slim. He wore platform shoes to look taller and padding under his clothes to look bigger. The people of Cape Town called Dr James Barry the kapok dokter, the cottonwool doctor.", "bbox": [69.9, 241.6, 497.1, 367.6], "size": 22.0}]$$),
    ('the-cottonwool-doctor', 7, $$“I would very much like to cut off your ears!” Dr James Barry would shout at anyone who challenged him. Dr James Barry even once fought a duel with pistols! Luckily, they both missed hitting each other. Why did the doctor fight so much? Margaret was brave, but she was also frightened. She knew that if anyone found out that she was Dr James Barry she would no longer be allowed to be a doctor. Everyone had to believe Dr James Barry was a man.$$, $$[{"role": "BODY", "text": "“I would very much like to cut off your ears!” Dr James Barry would shout at anyone who challenged him.", "bbox": [84.2, 150.6, 482.8, 224.6], "size": 22.0}, {"role": "BODY", "text": "Dr James Barry even once fought a duel with pistols! Luckily, they both missed hitting each other.", "bbox": [52.2, 254.6, 514.7, 302.6], "size": 22.0}, {"role": "BODY", "text": "Why did the doctor fight so much? Margaret was brave, but she was also frightened. She knew that if anyone found out that she was Dr James Barry she would no longer be allowed to be a doctor. Everyone had to believe Dr James Barry was a man.", "bbox": [51.2, 332.6, 515.7, 458.6], "size": 22.0}]$$),
    ('the-cottonwool-doctor', 8, $$Dr James Barry fought when he thought something was wrong. In Cape Town, people with leprosy were banished to Robben Island. The lepers were put on the island because people believed they could catch the disease from them very easily. Dirty houses and bad food made the lepers much sicker. Dr James Barry asked the leaders in Cape Town for cleaner living conditions and healthier food for the sick people on Robben Island.$$, $$[{"role": "BODY", "text": "Dr James Barry fought when he thought something was wrong.", "bbox": [59.4, 150.6, 507.6, 198.6], "size": 22.0}, {"role": "BODY", "text": "In Cape Town, people with leprosy were banished to Robben Island. The lepers were put on the island because people believed they could catch the disease from them very easily.", "bbox": [60.0, 228.6, 506.9, 328.6], "size": 22.0}, {"role": "BODY", "text": "Dirty houses and bad food made the lepers much sicker. Dr James Barry asked the leaders in Cape Town for cleaner living conditions and healthier food for the sick people on Robben Island.", "bbox": [68.1, 358.6, 498.8, 458.6], "size": 22.0}]$$),
    ('the-cottonwool-doctor', 9, $$Many years later Dr James Barry worked in a war hospital. Here he met Florence Nightingale, a nurse. Florence Nightingale was also known as The Lady with the Lamp, because she would check on wounded soldiers at night. She became famous during the war because she asked the army leaders for cleaner living conditions and healthier food for the soldiers. Dr James Barry had been asking for the same things for many years.$$, $$[{"role": "BODY", "text": "Many years later Dr James Barry worked in a war hospital. Here he met Florence Nightingale, a nurse.", "bbox": [56.0, 176.6, 510.9, 224.6], "size": 22.0}, {"role": "BODY", "text": "Florence Nightingale was also known as The Lady with the Lamp, because she would check on wounded soldiers at night. She became famous during the war because she asked the army leaders for cleaner living conditions and healthier food for the soldiers. Dr James Barry had been asking for the same things for many years.", "bbox": [54.5, 254.6, 512.4, 432.6], "size": 22.0}]$$),
    ('the-cottonwool-doctor', 10, $$Dr James Barry travelled all over the world. He worked in South Africa, St Helena, Barbados, Mauritius, Trinidad and Tobago, Malta, Corfu, Jamaica, Crimea, West Indies, Canada… 11 places in all. What exciting adventures he had!$$, $$[{"role": "BODY", "text": "Dr James Barry travelled all over the world. He worked in South Africa, St Helena, Barbados, Mauritius, Trinidad and Tobago, Malta, Corfu, Jamaica, Crimea, West Indies, Canada… 11 places in all.", "bbox": [77.2, 215.6, 489.8, 341.6], "size": 22.0}, {"role": "BODY", "text": "What exciting adventures he had!", "bbox": [137.9, 371.6, 429.0, 393.6], "size": 22.0}]$$),
    ('the-cottonwool-doctor', 11, $$People only found out that Dr James Barry was a woman when she died in 1865. In the same year, Dr Elizabeth Garret Andersen became the first woman to become a doctor in Great Britain. Dr James Barry has shown us that girls are clever. Girls are brave. Girls have dreams. Girls can fight for what they believe in. And girls can become doctors!$$, $$[{"role": "BODY", "text": "People only found out that Dr James Barry was a woman when she died in 1865.", "bbox": [68.8, 176.6, 498.2, 224.6], "size": 22.0}, {"role": "BODY", "text": "In the same year, Dr Elizabeth Garret Andersen became the first woman to become a doctor in Great Britain.", "bbox": [74.7, 254.6, 492.2, 328.6], "size": 22.0}, {"role": "BODY", "text": "Dr James Barry has shown us that girls are clever. Girls are brave. Girls have dreams. Girls can fight for what they believe in. And girls can become doctors!", "bbox": [50.6, 358.6, 516.3, 432.6], "size": 22.0}]$$),
    ('the-cottonwool-doctor', 12, $$$$, $$[]$$),
    ('the-cottonwool-doctor', 13, $$$$, $$[]$$),
    ('the-dream-pillow', 0, $$When the stars are out and the moon swings in the sky, and the light in my room is low, things are different.$$, $$[{"role": "BODY", "text": "When the stars are out and the moon swings in the sky, and the light in my room is low, things are different.", "bbox": [753.3, 272.5, 1017.1, 362.5], "size": 18.0}]$$),
    ('the-dream-pillow', 1, $$The pirate puppet waves his sword. The mango tree bends its branches. Even my teddy becomes a different sort of bear.$$, $$[{"role": "BODY", "text": "The pirate puppet waves his sword. The mango tree bends its branches. Even my teddy becomes a different sort of bear.", "bbox": [750.4, 388.6, 1046.9, 478.6], "size": 18.0}]$$),
    ('the-dream-pillow', 2, $$I keep very still in my cave of blankets or I call, “Maaamaaa! Daaaddyyy!” or I jump into their bed.$$, $$[{"role": "BODY", "text": "I keep very still in my cave of blankets or I call, “Maaamaaa! Daaaddyyy!” or I jump into their bed.", "bbox": [111.7, 332.8, 331.2, 422.8], "size": 18.0}]$$),
    ('the-dream-pillow', 3, $$I tell Mama about Pirate and Tree and Bear.$$, $$[{"role": "BODY", "text": "I tell Mama about Pirate and Tree and Bear.", "bbox": [117.0, 356.8, 321.1, 398.8], "size": 18.0}]$$),
    ('the-dream-pillow', 4, $$“You had a really bad dream.” “What’s a dream?” “When we sleep we think about our day, but everything gets mixed up. It feels real, but it’s not real.”$$, $$[{"role": "BODY", "text": "“You had a really bad dream.”", "bbox": [93.3, 297.4, 344.8, 315.4], "size": 18.0}, {"role": "BODY", "text": "“What’s a dream?”", "bbox": [139.3, 332.8, 298.7, 350.8], "size": 18.0}, {"role": "BODY", "text": "“When we sleep we think about our day, but everything gets mixed up. It feels real, but it’s not real.”", "bbox": [88.1, 368.1, 350.0, 458.1], "size": 18.0}]$$),
    ('the-dream-pillow', 5, $$“It is real!” “You know when we read a story together, it’s made up, but we laugh, or get scared or excited? A dream is the same.”$$, $$[{"role": "BODY", "text": "“It is real!”", "bbox": [153.1, 354.8, 249.5, 372.8], "size": 18.0}, {"role": "BODY", "text": "“You know when we read a story together, it’s made up, but we laugh, or get scared or excited? A dream is the same.”", "bbox": [65.4, 390.1, 337.3, 480.1], "size": 18.0}]$$),
    ('the-dream-pillow', 6, $$“You mean a dream is a story?” “Yes! But it happens at night. You put your head on the pillow, you fall asleep and then the story happens.” “So a dream is a story you find in your pillow?”$$, $$[{"role": "BODY", "text": "“You mean a dream is a story?”", "bbox": [112.4, 318.2, 375.4, 336.2], "size": 18.0}, {"role": "BODY", "text": "“Yes! But it happens at night. You put your head on the pillow, you fall asleep and then the story happens.”", "bbox": [82.0, 353.6, 405.8, 419.6], "size": 18.0}, {"role": "BODY", "text": "“So a dream is a story you find in your pillow?”", "bbox": [106.6, 436.9, 381.1, 478.9], "size": 18.0}]$$),
    ('the-dream-pillow', 7, $$“Yes!” “Can I put the stories in my pillow?” “You can.” “How?”$$, $$[{"role": "BODY", "text": "“Yes!”", "bbox": [259.0, 104.7, 313.6, 122.7], "size": 18.0}, {"role": "BODY", "text": "“Can I put the stories in my pillow?”", "bbox": [135.0, 140.0, 437.7, 158.0], "size": 18.0}, {"role": "BODY", "text": "“You can.”", "bbox": [241.3, 175.4, 331.4, 193.4], "size": 18.0}, {"role": "BODY", "text": "“How?”", "bbox": [254.3, 210.7, 318.3, 228.7], "size": 18.0}]$$),
    ('the-dream-pillow', 8, $$“Let’s write down all your best stories, fold up the paper and tuck it inside the pillow.”$$, $$[{"role": "BODY", "text": "“Let’s write down all your best stories, fold up the paper and tuck it inside the pillow.”", "bbox": [188.6, 262.6, 510.3, 328.6], "size": 18.0}]$$),
    ('the-dream-pillow', 9, $$$$, $$[]$$),
    ('the-dream-pillow', 10, $$$$, $$[]$$),
    ('the-dream-pillow', 11, $$When the stars are out and the moon swings in the sky, and the light in my room is low, things are different.$$, $$[{"role": "BODY", "text": "When the stars are out and the moon swings in the sky, and the light in my room is low, things are different.", "bbox": [753.3, 272.5, 1017.1, 362.5], "size": 18.0}]$$),
    ('the-dream-pillow', 12, $$$$, $$[]$$),
    ('the-dream-pillow', 13, $$for ilyas tomÁs$$, $$[{"role": "BODY", "text": "for ilyas tomÁs", "bbox": [250.4, 368.3, 329.1, 386.3], "size": 18.0}]$$),
    ('the-fish-and-chickens-wedding', 0, $$There once lived a chicken, called Cikizwa, who was an orphan. One day Cikizwa was out looking for food when she saw a mole coming out of his hole. She started speaking to the mole, but he ignored her.$$, $$[{"role": "BODY", "text": "There once lived a chicken, called Cikizwa, who was an orphan.", "bbox": [87.7, 232.6, 479.4, 272.1], "size": 18.0}, {"role": "BODY", "text": "One day Cikizwa was out looking for food when she saw a mole coming out of his hole. She started speaking to the mole, but he ignored her.", "bbox": [74.6, 297.4, 492.6, 358.6], "size": 18.0}]$$),
    ('the-fish-and-chickens-wedding', 1, $$Tears poured down Cikizwa’s face as she wept bitterly, and so the mole apologised for hurting her feelings. Then he bought some cooldrink and scones. They ate and drank them together and then they both felt much happier.$$, $$[{"role": "BODY", "text": "Tears poured down Cikizwa’s face as she wept bitterly, and so the mole apologised for hurting her feelings.", "bbox": [87.6, 70.8, 479.5, 132.0], "size": 18.0}, {"role": "BODY", "text": "Then he bought some cooldrink and scones. They ate and drank them together and then they both felt much happier.", "bbox": [647.4, 70.8, 1053.6, 132.0], "size": 18.0}]$$),
    ('the-fish-and-chickens-wedding', 2, $$From that day on, the mole and Cikizwa became great friends. The friends often hugged each other tightly. They loved and looked after each other.$$, $$[{"role": "BODY", "text": "From that day on, the mole and Cikizwa became great friends. The friends often hugged each other tightly. They loved and looked after each other.", "bbox": [73.1, 250.1, 494.1, 311.3], "size": 18.0}]$$),
    ('the-fish-and-chickens-wedding', 3, $$One evening, Cikizwa said goodbye to her friend and went home. That night, Cikizwa had a dream. She heard her mother’s voice asking, “When is Cikizwa getting married?” “Oh, I must have been dreaming,” said Cikizwa as she woke up. Now, in the place where Cikizwa lived, there was a cruel elephant.$$, $$[{"role": "BODY", "text": "One evening, Cikizwa said goodbye to her friend and went home. That night, Cikizwa had a dream.", "bbox": [77.5, 70.8, 489.6, 110.4], "size": 18.0}, {"role": "BODY", "text": "She heard her mother’s voice asking, “When is Cikizwa getting married?” “Oh, I must have been dreaming,” said Cikizwa as she woke up.", "bbox": [130.8, 135.6, 436.3, 218.4], "size": 18.0}, {"role": "BODY", "text": "Now, in the place where Cikizwa lived, there was a cruel elephant.", "bbox": [73.6, 459.1, 493.5, 498.7], "size": 18.0}]$$),
    ('the-fish-and-chickens-wedding', 4, $$Elephant often said really unkind things to Cikizwa to try and make her unhappy. One morning, when Cikizwa greeted Elephant, he snubbed her and said, “Ha, ha, ha! Go away, you orphan! What do you want from me? You’re so skinny. It’s as if you haven’t had enough mealies to eat!” Cikizwa was heartbroken.$$, $$[{"role": "BODY", "text": "Elephant often said really unkind things to Cikizwa to try and make her unhappy. One morning, when Cikizwa greeted Elephant, he snubbed her and said, “Ha, ha, ha! Go away, you orphan! What do you want from me? You’re so skinny. It’s as if you haven’t had enough mealies to eat!” Cikizwa was heartbroken.", "bbox": [73.3, 221.8, 493.8, 369.4], "size": 18.0}]$$),
    ('the-fish-and-chickens-wedding', 5, $$On her way home, she met Gusha Bhoqo. As soon as she saw the kind sheep, she poured out her heart to him. She told him about what Elephant had said to her. Gusha comforted the chicken and he was even able to make her smile a little. Then Gusha invited Cikizwa to have supper at his home. They had tasty samp, cooked with beans for supper. Afterwards, Cikizwa danced joyfully with the Gusha family as the music played. She danced so much that she sent the dust flying and forgot all her troubles!$$, $$[{"role": "BODY", "text": "On her way home, she met Gusha Bhoqo. As soon as she saw the kind sheep, she poured out her heart to him. She told him about what Elephant had said to her.", "bbox": [67.6, 70.8, 499.5, 153.6], "size": 18.0}, {"role": "BODY", "text": "Gusha comforted the chicken and he was even able to make her smile a little. Then Gusha invited Cikizwa to have supper at his home. They had tasty samp, cooked with beans for supper. Afterwards, Cikizwa danced joyfully with the Gusha family as the music played. She danced so much that she sent the dust flying and forgot all her troubles!", "bbox": [57.0, 394.3, 510.1, 541.9], "size": 18.0}]$$),
    ('the-fish-and-chickens-wedding', 6, $$The next day it rained and rained. It rained so heavily that many animals were swept away by the nearby river. Cikizwa was safe in her little coop because her father had been clever enough to build a drain nearby so that it didn’t get flooded.$$, $$[{"role": "BODY", "text": "The next day it rained and rained. It rained so heavily that many animals were swept away by the nearby river. Cikizwa was safe in her little coop because her father had been clever enough to build a drain nearby so that it didn’t get flooded.", "bbox": [73.0, 232.6, 494.2, 336.9], "size": 18.0}]$$),
    ('the-fish-and-chickens-wedding', 7, $$But Cikizwa still felt sad about what had happened to some of her friends. Once the rain stopped, beautiful, colourful flowers appeared and there was a cool breeze. Cikizwa was out enjoying the sunshine when she saw Elephant limping along and crying loudly. Kind Cikizwa quickly called an ambulance.$$, $$[{"role": "BODY", "text": "But Cikizwa still felt sad about what had happened to some of her friends.", "bbox": [72.8, 210.9, 494.3, 250.6], "size": 18.0}, {"role": "BODY", "text": "Once the rain stopped, beautiful, colourful flowers appeared and there was a cool breeze. Cikizwa was out enjoying the sunshine when she saw Elephant limping along and crying loudly. Kind Cikizwa quickly called an ambulance.", "bbox": [74.3, 275.8, 492.8, 380.1], "size": 18.0}]$$),
    ('the-fish-and-chickens-wedding', 8, $$When the ambulance arrived, Elephant got the help he needed. His leg was bandaged and he was given an injection to help with the pain. As soon as Elephant started to feel better, he thanked Cikizwa for her kindness. Then he said, “Cikizwa, my child, never change who you are. Keep on respecting and loving everyone.”$$, $$[{"role": "BODY", "text": "When the ambulance arrived, Elephant got the help he needed. His leg was bandaged and he was given an injection to help with the pain. As soon as Elephant started to feel better, he thanked Cikizwa for her kindness.", "bbox": [70.9, 200.2, 496.3, 304.6], "size": 18.0}, {"role": "BODY", "text": "Then he said, “Cikizwa, my child, never change who you are. Keep on respecting and loving everyone.”", "bbox": [88.7, 329.8, 478.4, 390.9], "size": 18.0}]$$),
    ('the-fish-and-chickens-wedding', 9, $$Some time later, Cikizwa went down to the river to enjoy herself. There were already a few people and animals there. Some of them were fishing, and then braaiing the fish they had caught. They ate the fish and fluffy freshly-baked roosterkoek. Cikizwa noticed a beautiful fish and she found out that his name was Gumbi. Gumbi and Cikizwa got to know each other and quickly became friends. Cikizwa even decided to stop eating fish out of respect for Gumbi. Some of the other animals laughed at them and said, “How can a fish and a chicken be friends?”$$, $$[{"role": "BODY", "text": "Some time later, Cikizwa went down to the river to enjoy herself. There were already a few people and animals there. Some of them were fishing, and then braaiing the fish they had caught. They ate the fish and fluffy freshly-baked roosterkoek.", "bbox": [251.4, 70.8, 502.8, 261.6], "size": 18.0}, {"role": "BODY", "text": "Cikizwa noticed a beautiful fish and she found out that his name was Gumbi.", "bbox": [247.5, 286.8, 506.7, 348.0], "size": 18.0}, {"role": "BODY", "text": "Gumbi and Cikizwa got to know each other and quickly became friends. Cikizwa even decided to stop eating fish out of respect for Gumbi.", "bbox": [635.5, 70.8, 903.8, 175.2], "size": 18.0}, {"role": "BODY", "text": "Some of the other animals laughed at them and said, “How can a fish and a chicken be friends?”", "bbox": [625.8, 200.4, 913.6, 261.6], "size": 18.0}]$$),
    ('the-fish-and-chickens-wedding', 10, $$But Gumbi and Cikizwa didn’t care. They became even closer. Gumbi taught Cikizwa how to swim and dive, and Cikizwa taught Gumbi how to scratch in the sand for food. Eventually Gumbi asked Cikizwa to marry him. Cikizwa agreed immediately. Together they decided to have their wedding the following Saturday at a place that they both loved near the river.$$, $$[{"role": "BODY", "text": "But Gumbi and Cikizwa didn’t care. They became even closer. Gumbi taught Cikizwa how to swim and dive, and Cikizwa taught Gumbi how to scratch in the sand for food.", "bbox": [81.1, 189.3, 486.0, 272.1], "size": 18.0}, {"role": "BODY", "text": "Eventually Gumbi asked Cikizwa to marry him. Cikizwa agreed immediately. Together they decided to have their wedding the following Saturday at a place that they both loved near the river.", "bbox": [91.9, 297.4, 475.2, 401.8], "size": 18.0}]$$),
    ('the-fish-and-chickens-wedding', 11, $$Their wedding day arrived. The sun was blazing hot. What a wonderful wedding it was! The animal choir sang beautifully. Iguanas, whales, crocodiles, seals, sharks, dolphins, sheep, cattle, dogs, antelopes, hares, porcupines, water snakes and other animals all sang together: “It is enjoyable here at the wedding of the fish. It is enjoyable here at the wedding of the chicken!”$$, $$[{"role": "BODY", "text": "Their wedding day arrived. The sun was blazing hot. What a wonderful wedding it was!", "bbox": [85.9, 167.8, 481.2, 207.3], "size": 18.0}, {"role": "BODY", "text": "The animal choir sang beautifully. Iguanas, whales, crocodiles, seals, sharks, dolphins, sheep, cattle, dogs, antelopes, hares, porcupines, water snakes and other animals all sang together:", "bbox": [75.9, 232.6, 491.2, 315.4], "size": 18.0}, {"role": "BODY", "text": "“It is enjoyable here at the wedding of the fish. It is enjoyable here at the wedding of the chicken!”", "bbox": [70.9, 340.6, 496.1, 380.1], "size": 18.0}]$$),
    ('the-fish-and-chickens-wedding', 12, $$$$, $$[]$$),
    ('the-fish-and-chickens-wedding', 13, $$$$, $$[]$$),
    ('the-fish-that-couldnt-swim', 0, $$There once was a boy who could run and jump and climb. He could even make a noise like a seagull. But he couldn’t swim. And oh, how he wanted to.$$, $$[{"role": "BODY", "text": "There once was a boy who could run and jump and climb. He could even make a noise like a seagull.", "bbox": [59.0, 138.8, 507.9, 246.8], "size": 28.0}, {"role": "BODY", "text": "But he couldn’t swim.", "bbox": [623.6, 140.6, 888.4, 168.6], "size": 28.0}, {"role": "BODY", "text": "And oh, how he wanted to.", "bbox": [623.6, 220.6, 792.3, 288.6], "size": 28.0}]$$),
    ('the-fish-that-couldnt-swim', 1, $$Then one day ... ... he noticed a fish that couldn’t swim either.$$, $$[{"role": "BODY", "text": "Then one day ...", "bbox": [56.7, 101.4, 249.8, 129.4], "size": 28.0}, {"role": "BODY", "text": "... he noticed a fish that couldn’t swim either.", "bbox": [623.6, 99.9, 780.5, 287.9], "size": 28.0}]$$),
    ('the-fish-that-couldnt-swim', 2, $$He wanted to help the fish.$$, $$[{"role": "BODY", "text": "He wanted to help the fish.", "bbox": [187.4, 170.4, 379.5, 238.4], "size": 28.0}]$$),
    ('the-fish-that-couldnt-swim', 3, $$So he put it in the water ...$$, $$[{"role": "BODY", "text": "So he put it in the water ...", "bbox": [689.3, 271.5, 1011.5, 299.5], "size": 28.0}]$$),
    ('the-fish-that-couldnt-swim', 4, $$... and the fish came alive!$$, $$[{"role": "BODY", "text": "... and the fish came alive!", "bbox": [125.8, 274.4, 441.1, 302.4], "size": 28.0}]$$),
    ('the-fish-that-couldnt-swim', 5, $$But the boy also wanted to learn to swim.$$, $$[{"role": "BODY", "text": "But the boy also wanted to learn to swim.", "bbox": [701.5, 173.6, 999.3, 241.6], "size": 28.0}]$$),
    ('the-fish-that-couldnt-swim', 6, $$So the fish showed the boy how to put his mouth in the water and blow .$$, $$[{"role": "BODY", "text": "So the fish showed the boy how to put his mouth in the water and blow .", "bbox": [56.7, 156.1, 253.2, 434.8], "size": 49.5}]$$),
    ('the-fish-that-couldnt-swim', 7, $$What fun they had!$$, $$[{"role": "BODY", "text": "What fun they had!", "bbox": [192.1, 127.0, 430.1, 154.9], "size": 28.0}]$$),
    ('the-fish-that-couldnt-swim', 8, $$The next day, the boy remembered what the fish had taught him.$$, $$[{"role": "BODY", "text": "The next day, the boy remembered what the fish had taught him.", "bbox": [636.3, 140.3, 1064.5, 208.3], "size": 28.0}]$$),
    ('the-fish-that-couldnt-swim', 9, $$$$, $$[]$$),
    ('the-fish-that-couldnt-swim', 10, $$And so the boy who could run and jump and climb, and even make a noise like a seagull, learned to swim like a fish.$$, $$[{"role": "BODY", "text": "And so the boy who could run and jump and climb, and even make a noise like a seagull, learned to swim like a fish.", "bbox": [60.5, 214.3, 506.4, 362.4], "size": 28.0}]$$),
    ('the-fish-that-couldnt-swim', 11, $$$$, $$[]$$),
    ('the-fish-that-couldnt-swim', 12, $$$$, $$[]$$),
    ('the-fish-that-couldnt-swim', 13, $$$$, $$[]$$),
    ('the-great-cake-contest', 0, $$Lucky loves cake. He is so happy that the Great Cake Contest is in town. “What cake can I bake?” he thinks.$$, $$[{"role": "BODY", "text": "Lucky loves cake. He is so happy that the Great Cake Contest is in town.", "bbox": [659.5, 108.2, 990.6, 221.6], "size": 27.0}, {"role": "BODY", "text": "“What cake can I bake?” he thinks.", "bbox": [659.5, 377.0, 1000.7, 441.8], "size": 26.0}]$$),
    ('the-great-cake-contest', 1, $$“I know. I can make a pancake!” shouts Lucky. He walks to Pontsho’s house to share his idea, but she already beat him to it.$$, $$[{"role": "BODY", "text": "“I know. I can make a pancake!” shouts Lucky.", "bbox": [56.7, 300.4, 486.2, 366.5], "size": 25.5}, {"role": "BODY", "text": "He walks to Pontsho’s house to share his idea, but she already beat him to it.", "bbox": [56.7, 398.7, 488.4, 449.3], "size": 23.0}]$$),
    ('the-great-cake-contest', 2, $$“Or, what if I made a carrot cake?” he wonders. He goes to tell Nini his plan, but she had the same idea.$$, $$[{"role": "BODY", "text": "“Or, what if I made a carrot cake?” he wonders.", "bbox": [56.7, 304.0, 508.7, 358.1], "size": 25.5}, {"role": "BODY", "text": "He goes to tell Nini his plan, but she had the same idea.", "bbox": [56.7, 390.3, 450.7, 440.9], "size": 23.0}]$$),
    ('the-great-cake-contest', 3, $$“What about baking a black forest cake?” He rushes to tell Kima what he’s come up with, but he’s too late.$$, $$[{"role": "BODY", "text": "“What about baking a black forest cake?”", "bbox": [56.7, 307.5, 434.6, 369.1], "size": 28.0}, {"role": "BODY", "text": "He rushes to tell Kima what he’s come up with, but he’s too late.", "bbox": [56.7, 399.8, 411.3, 450.4], "size": 23.0}]$$),
    ('the-great-cake-contest', 4, $$On the way to Nthabi’s house, he thinks: “Let me just make a Christmas cake!” But Nthabi already made that happen.$$, $$[{"role": "BODY", "text": "On the way to Nthabi’s house, he thinks: “Let me just make a Christmas cake!”", "bbox": [56.7, 182.7, 500.2, 274.4], "size": 26.8}, {"role": "BODY", "text": "But Nthabi already made that happen.", "bbox": [56.7, 305.1, 268.6, 355.7], "size": 23.0}]$$),
    ('the-great-cake-contest', 5, $$“What other cake can I bake?” he asks himself. “How about a chocolate mousse cake?” He arrives at Linda’s house but oh no! He was too slow.$$, $$[{"role": "BODY", "text": "“What other cake can I bake?” he asks himself.", "bbox": [56.7, 169.8, 251.4, 253.9], "size": 23.0}, {"role": "BODY", "text": "“How about a chocolate mousse cake?”", "bbox": [56.7, 294.7, 381.4, 356.3], "size": 28.0}, {"role": "BODY", "text": "He arrives at Linda’s house but oh no! He was too slow.", "bbox": [56.7, 386.9, 474.8, 437.6], "size": 23.0}]$$),
    ('the-great-cake-contest', 6, $$Lucky gets an idea. “I will make a roly-poly cake.” He gets to Zola’s house but she’s way ahead of him.$$, $$[{"role": "BODY", "text": "Lucky gets an idea. “I will make a roly-poly cake.”", "bbox": [56.7, 270.6, 456.6, 328.7], "size": 25.5}, {"role": "BODY", "text": "He gets to Zola’s house but she’s way ahead of him.", "bbox": [56.7, 359.4, 360.2, 410.0], "size": 23.0}]$$),
    ('the-great-cake-contest', 7, $$Lucky feels sad when he gets home because he is out of ideas. He asks his family to help him think about what great cake he can bake.$$, $$[{"role": "BODY", "text": "Lucky feels sad when he gets home because he is out of ideas. He asks his family to help him think about what great cake he can bake.", "bbox": [623.6, 168.1, 1044.4, 273.9], "size": 23.0}]$$),
    ('the-great-cake-contest', 8, $$Mama, Papa and his big sister Musa all put their heads together to help him enter the Great Cake Contest.$$, $$[{"role": "BODY", "text": "Mama, Papa and his big sister Musa all put their heads together to help him enter the Great Cake Contest.", "bbox": [56.7, 212.0, 387.6, 317.8], "size": 23.0}]$$),
    ('the-great-cake-contest', 9, $$The cake is so big, so wide, so tall ... ... that it begins to wobble, wobble, wobble and fall!$$, $$[{"role": "BODY", "text": "The cake is so big, so wide, so tall ...", "bbox": [779.5, 156.8, 902.2, 262.6], "size": 23.0}, {"role": "BODY", "text": "... that it begins to wobble, wobble, wobble and fall!", "bbox": [779.5, 294.8, 1072.2, 345.4], "size": 23.0}]$$),
    ('the-great-cake-contest', 10, $$Oh no! Everyone at the Great Cake Contest is covered in cake. Where are the judges? Where are the contestants? Where is Lucky?$$, $$[{"role": "BODY", "text": "Oh no! Everyone at the Great Cake Contest is covered in cake.", "bbox": [56.7, 73.9, 399.2, 179.3], "size": 31.0}, {"role": "BODY", "text": "Where are the judges?", "bbox": [273.5, 243.3, 444.8, 297.5], "size": 25.0}, {"role": "BODY", "text": "Where are the contestants?", "bbox": [623.6, 75.1, 958.3, 100.1], "size": 25.0}, {"role": "SFX", "text": "Where is Lucky?", "bbox": [623.6, 174.2, 804.0, 271.0], "size": 44.0}]$$),
    ('the-great-cake-contest', 11, $$The judges munch and chomp their way out and everyone agrees: Lucky is the winner of the Great Cake Contest!$$, $$[{"role": "BODY", "text": "The judges munch and chomp their way out and everyone agrees:", "bbox": [86.0, 216.7, 480.9, 267.3], "size": 23.0}, {"role": "SFX", "text": "Lucky is the winner of the Great Cake Contest!", "bbox": [92.4, 300.0, 474.6, 368.2], "size": 31.0}]$$),
    ('the-great-cake-contest', 12, $$$$, $$[]$$),
    ('the-great-cake-contest', 13, $$What cake would you bake?$$, $$[{"role": "SFX", "text": "What cake would you bake?", "bbox": [102.2, 262.8, 464.7, 359.6], "size": 44.0}]$$),
    ('the-great-tidy-up', 0, $$‘We are going to have so much fun while Gogo is having a nap,’ says big sister Khwezi. ‘Ooh yes!’ says little brother Mzamo. ‘What will we do?’ z z z$$, $$[{"role": "BODY", "text": "‘We are going to have so much fun while Gogo is having a nap,’ says big sister Khwezi.", "bbox": [81.8, 155.1, 485.1, 233.2], "size": 23.0}, {"role": "BODY", "text": "‘Ooh yes!’ says little brother Mzamo.", "bbox": [82.0, 265.4, 485.0, 288.4], "size": 23.0}, {"role": "BODY", "text": "‘What will we do?’", "bbox": [184.5, 348.2, 382.4, 371.2], "size": 23.0}, {"role": "BODY", "text": "z", "bbox": [758.0, 20.2, 772.4, 47.9], "size": 27.6}, {"role": "BODY", "text": "z", "bbox": [729.7, 51.3, 742.0, 74.9], "size": 23.6}, {"role": "BODY", "text": "z", "bbox": [740.8, 91.2, 748.8, 106.5], "size": 15.4}]$$),
    ('the-great-tidy-up', 1, $$‘We will clean the house for Papa and Mama while they are out.’ ‘That’s no fun,’ says Mzamo. ‘Uh uh, no. Not me. I don’t want to clean up!’$$, $$[{"role": "BODY", "text": "‘We will clean the house for Papa and Mama while they are out.’", "bbox": [100.2, 138.4, 466.8, 189.0], "size": 23.0}, {"role": "BODY", "text": "‘That’s no fun,’ says Mzamo.", "bbox": [126.8, 248.8, 440.2, 271.8], "size": 23.0}, {"role": "BODY", "text": "‘Uh uh, no. Not me. I don’t want to clean up!’", "bbox": [146.2, 304.0, 420.8, 382.2], "size": 23.0}]$$),
    ('the-great-tidy-up', 2, $$‘But Papa and Mama will be so proud. Let me show you how much fun we will have!’ says Khwezi.$$, $$[{"role": "BODY", "text": "‘But Papa and Mama will be so proud.", "bbox": [47.3, 83.8, 464.4, 106.8], "size": 23.0}, {"role": "BODY", "text": "Let me show you how much fun we will have!’ says Khwezi.", "bbox": [42.0, 139.0, 469.7, 189.6], "size": 23.0}]$$),
    ('the-great-tidy-up', 3, $$‘First we will put the toys away!’$$, $$[{"role": "BODY", "text": "‘First we will put the toys away!’", "bbox": [215.9, 265.1, 436.8, 315.7], "size": 23.0}]$$),
    ('the-great-tidy-up', 4, $$‘Now we will sweep the stoep!’$$, $$[{"role": "BODY", "text": "‘Now we will sweep the stoep!’", "bbox": [59.6, 480.9, 393.9, 503.9], "size": 23.0}]$$),
    ('the-great-tidy-up', 5, $$‘Now we will wash the dishes!’$$, $$[{"role": "BODY", "text": "‘Now we will wash the dishes!’", "bbox": [719.1, 435.6, 1046.9, 458.6], "size": 23.0}]$$),
    ('the-great-tidy-up', 6, $$‘Now we will wash the windows!’$$, $$[{"role": "BODY", "text": "‘Now we will wash the windows!’", "bbox": [31.4, 265.1, 243.5, 315.7], "size": 23.0}]$$),
    ('the-great-tidy-up', 7, $$‘Now we will polish the floor!’ z z z$$, $$[{"role": "BODY", "text": "‘Now we will polish the floor!’", "bbox": [72.2, 86.5, 252.4, 137.2], "size": 23.0}, {"role": "BODY", "text": "z", "bbox": [424.5, 26.6, 434.1, 46.6], "size": 20.0}, {"role": "BODY", "text": "z", "bbox": [401.4, 56.9, 410.1, 74.9], "size": 18.0}, {"role": "BODY", "text": "z", "bbox": [413.9, 92.9, 419.2, 103.9], "size": 11.0}]$$),
    ('the-great-tidy-up', 8, $$‘Now we will wash the clothes!’$$, $$[{"role": "BODY", "text": "‘Now we will wash the clothes!’", "bbox": [92.3, 393.0, 430.7, 416.0], "size": 23.0}]$$),
    ('the-great-tidy-up', 9, $$‘Now we will hang the clothes up!’$$, $$[{"role": "BODY", "text": "‘Now we will hang the clothes up!’", "bbox": [97.5, 278.9, 469.5, 301.9], "size": 23.0}]$$),
    ('the-great-tidy-up', 10, $$“SURPRISE!”$$, $$[{"role": "SFX", "text": "“SURPRISE!”", "bbox": [323.4, 129.5, 529.9, 164.5], "size": 35.0}]$$),
    ('the-great-tidy-up', 11, $$‘I have been watching them the whole time and they have been little angels!’ says Gogo.$$, $$[{"role": "BODY", "text": "‘I have been watching them the whole time and they have been little angels!’ says Gogo.", "bbox": [71.8, 158.1, 495.2, 236.3], "size": 23.0}]$$),
    ('the-great-tidy-up', 12, $$$$, $$[]$$),
    ('the-great-tidy-up', 13, $$$$, $$[]$$),
    ('the-lazy-ant', 0, $$It was summer time and most of the ants in Ant City were collecting food. But Lazy Ant was lying on his back on top of a rock basking in the sun.$$, $$[{"role": "BODY", "text": "It was summer time and most of the ants in Ant City were collecting food.", "bbox": [56.7, 210.0, 508.1, 260.6], "size": 23.0}, {"role": "BODY", "text": "But Lazy Ant was lying on his back on top of a rock basking in the sun.", "bbox": [56.7, 292.8, 489.7, 343.4], "size": 23.0}]$$),
    ('the-lazy-ant', 1, $$As Lazy Ant’s mother and sisters were busy collecting food, he just glanced at them, whistling and waiting for them to finish.$$, $$[{"role": "BODY", "text": "As Lazy Ant’s mother and sisters were busy collecting food, he just glanced at them, whistling and waiting for them to finish.", "bbox": [728.4, 235.1, 1047.4, 340.9], "size": 23.0}]$$),
    ('the-lazy-ant', 2, $$But when it was time to eat, Lazy Ant would suddenly jump up.$$, $$[{"role": "BODY", "text": "But when it was time to eat, Lazy Ant would suddenly jump up.", "bbox": [56.7, 262.7, 473.3, 313.3], "size": 23.0}]$$),
    ('the-lazy-ant', 3, $$Lazy Ant always complained when he was given work to do. In fact, he was so lazy that he would even cry! Instead of working, Lazy Ant would chat non-stop, and so when it was time to go home, his work was left unfinished.$$, $$[{"role": "BODY", "text": "Lazy Ant always complained when he was given work to do. In fact, he was so lazy that he would even cry!", "bbox": [623.6, 193.7, 1043.5, 271.9], "size": 23.0}, {"role": "BODY", "text": "Instead of working, Lazy Ant would chat non-stop, and so when it was time to go home, his work was left unfinished.", "bbox": [623.6, 304.1, 1004.8, 382.3], "size": 23.0}]$$),
    ('the-lazy-ant', 4, $$One day Lazy Ant’s mother found him sitting on a rock as usual.$$, $$[{"role": "BODY", "text": "One day Lazy Ant’s mother found him sitting on a rock as usual.", "bbox": [623.6, 262.7, 1076.8, 313.3], "size": 23.0}]$$),
    ('the-lazy-ant', 5, $$His mother was angry and she punished him. Then she told him to quickly fill a sack with food. Lazy Ant grumbled as he began working. He knew that he would not be getting any food if he didn’t work.$$, $$[{"role": "BODY", "text": "His mother was angry and she punished him.", "bbox": [56.7, 207.5, 487.0, 230.5], "size": 23.0}, {"role": "BODY", "text": "Then she told him to quickly fill a sack with food. Lazy Ant grumbled as he began working. He knew that he would not be getting any food if he didn’t work.", "bbox": [56.7, 262.7, 504.7, 368.5], "size": 23.0}]$$),
    ('the-lazy-ant', 6, $$By the end of that day, Lazy Ant’s sack was full. His mother was very happy to see that her son had worked so hard.$$, $$[{"role": "BODY", "text": "By the end of that day, Lazy Ant’s sack was full. His mother was very happy to see that her son had worked so hard.", "bbox": [623.6, 144.1, 1060.7, 222.3], "size": 23.0}]$$),
    ('the-lazy-ant', 7, $$Lazy Ant’s mother prepared a special meal for supper to reward her son. He enjoyed the meal along with the other ants who had worked hard all day.$$, $$[{"role": "BODY", "text": "Lazy Ant’s mother prepared a special meal for supper to reward her son. He enjoyed the meal along with the other ants who had worked hard all day.", "bbox": [637.8, 235.1, 1084.6, 340.9], "size": 23.0}]$$),
    ('the-lazy-ant', 8, $$The next morning, Lazy Ant was the first one to wake up and he prepared breakfast for his mother.$$, $$[{"role": "BODY", "text": "The next morning, Lazy Ant was the first one to wake up and he prepared breakfast for his mother.", "bbox": [93.5, 245.4, 439.1, 323.6], "size": 23.0}]$$),
    ('the-lazy-ant', 9, $$All the other ants were shocked by the change in Lazy Ant’s behaviour. He went up and down offering help to any ant who needed it.$$, $$[{"role": "BODY", "text": "All the other ants were shocked by the change in Lazy Ant’s behaviour. He went up and down offering help to any ant who needed it.", "bbox": [79.1, 107.6, 471.8, 213.4], "size": 23.0}]$$),
    ('the-lazy-ant', 10, $$The elders of Ant City even celebrated the change in Lazy Ant’s behaviour with him.$$, $$[{"role": "BODY", "text": "The elders of Ant City even celebrated the change in Lazy Ant’s behaviour with him.", "bbox": [56.7, 123.1, 446.3, 173.7], "size": 23.0}]$$),
    ('the-lazy-ant', 11, $$And from that day, Lazy Ant saw the importance of working together with others. Working together creates peace, joy and harmony.$$, $$[{"role": "BODY", "text": "And from that day, Lazy Ant saw the importance of working together with others.", "bbox": [629.3, 221.3, 1044.9, 271.9], "size": 23.0}, {"role": "BODY", "text": "Working together creates peace, joy and harmony.", "bbox": [629.3, 304.1, 964.6, 354.7], "size": 23.0}]$$),
    ('the-lazy-ant', 12, $$$$, $$[]$$),
    ('the-lazy-ant', 13, $$$$, $$[]$$),
    ('the-lost-laugh', 0, $$Spotty the Hyena is very sad. He has lost his laugh.$$, $$[{"role": "BODY", "text": "Spotty the Hyena is very sad. He has lost his laugh.", "bbox": [660.7, 105.4, 1040.1, 168.4], "size": 30.0}]$$),
    ('the-lost-laugh', 1, $$“Please help me find my laugh, Giraffe.” “I can’t hear a laugh up here.”$$, $$[{"role": "BODY", "text": "“Please help me find my laugh, Giraffe.”", "bbox": [68.4, 105.3, 335.5, 168.3], "size": 30.0}, {"role": "BODY", "text": "“I can’t hear", "bbox": [761.0, 65.3, 974.8, 123.5], "size": 41.8}, {"role": "BODY", "text": "a laugh", "bbox": [801.5, 164.6, 930.9, 215.5], "size": 41.7}, {"role": "BODY", "text": "up here.”", "bbox": [789.2, 259.1, 947.2, 312.4], "size": 41.8}]$$),
    ('the-lost-laugh', 2, $$“Please help me find my laugh, Hippo.” “I can’t hear a laugh down here.”$$, $$[{"role": "BODY", "text": "“Please help me find my laugh, Hippo.”", "bbox": [96.5, 82.0, 363.6, 145.0], "size": 30.0}, {"role": "BODY", "text": "“I can’t hear a laugh down here.”", "bbox": [111.4, 196.5, 402.1, 352.7], "size": 35.0}]$$),
    ('the-lost-laugh', 3, $$“Please my laugh, help Warthog.” me find “I can’t hear a laugh in here.”$$, $$[{"role": "BODY", "text": "“Please my laugh, help Warthog.” me find", "bbox": [194.5, 73.5, 461.7, 136.5], "size": 30.0}, {"role": "BODY", "text": "“I can’t hear a laugh in here.”", "bbox": [648.6, 78.3, 878.3, 204.1], "size": 37.0}]$$),
    ('the-lost-laugh', 4, $$“Please help me find my laugh, Monkey.” “How did you lose it?”$$, $$[{"role": "BODY", "text": "“Please help me find my laugh, Monkey.”", "bbox": [149.9, 113.5, 417.0, 176.5], "size": 30.0}, {"role": "BODY", "text": "“How did you lose it?”", "bbox": [139.6, 212.5, 427.5, 242.5], "size": 30.0}]$$),
    ('the-lost-laugh', 5, $$“When I laugh, you can see my big teeth. That makes everyone frightened,” said Spotty. “Then I got sad and my laugh just disappeared.”$$, $$[{"role": "BODY", "text": "“When I laugh, you can see my big teeth. That makes everyone frightened,” said Spotty.", "bbox": [78.1, 65.3, 488.8, 161.3], "size": 30.0}, {"role": "BODY", "text": "“Then I got sad and my laugh just disappeared.”", "bbox": [94.3, 197.3, 472.6, 260.3], "size": 30.0}]$$),
    ('the-lost-laugh', 6, $$“I can’t find it anywhere!” “But you were looking in the wrong place.”$$, $$[{"role": "SFX", "text": "“I can’t find it anywhere!”", "bbox": [152.9, 162.4, 413.2, 314.2], "size": 45.4}, {"role": "BODY", "text": "“But you were looking in the wrong place.”", "bbox": [626.4, 273.2, 915.6, 336.2], "size": 30.0}]$$),
    ('the-lost-laugh', 7, $$Monkey jumped out of the tree and picked up a feather. Then she began to tickle Spotty all over.$$, $$[{"role": "BODY", "text": "Monkey", "bbox": [108.8, 61.0, 219.8, 96.7], "size": 31.4}, {"role": "BODY", "text": "jumped", "bbox": [112.4, 128.4, 214.2, 163.6], "size": 31.3}, {"role": "BODY", "text": "out of the tree", "bbox": [66.7, 194.7, 261.1, 234.7], "size": 30.9}, {"role": "BODY", "text": "and picked up a feather.", "bbox": [72.8, 279.4, 255.4, 342.4], "size": 30.0}, {"role": "BODY", "text": "Then she began to tickle Spotty all over.", "bbox": [689.6, 65.0, 1011.2, 128.0], "size": 30.0}]$$),
    ('the-lost-laugh', 8, $$Slowly Spotty started smiling, and then he let out a big, loud laugh. He laughed and laughed until he was rolling around on the ground.$$, $$[{"role": "BODY", "text": "Slowly Spotty started smiling, and then he let out a big, loud laugh.", "bbox": [671.1, 227.7, 1026.9, 323.7], "size": 30.0}, {"role": "BODY", "text": "He laughed and laughed until he was rolling around on the ground.", "bbox": [671.1, 359.7, 1017.4, 455.7], "size": 30.0}]$$),
    ('the-lost-laugh', 9, $$All the other animals started laughing too.$$, $$[{"role": "BODY", "text": "All the other animals started laughing too.", "bbox": [708.7, 286.1, 979.3, 349.1], "size": 30.0}]$$),
    ('the-lost-laugh', 10, $$“Where did you find his laugh?” they asked. “His laugh was inside him all the time. I just made him happy and out it came.”$$, $$[{"role": "BODY", "text": "“Where did you find his laugh?” they asked.", "bbox": [56.7, 58.0, 467.7, 121.0], "size": 30.0}, {"role": "BODY", "text": "“His laugh was inside him all the time. I just made him happy and out it came.”", "bbox": [56.7, 439.0, 476.1, 535.0], "size": 30.0}]$$),
    ('the-lost-laugh', 11, $$They all laughed and laughed so that their teeth showed too. “I’ll n eve r lose my laugh again,” said Spotty the happy Hyena.$$, $$[{"role": "BODY", "text": "They all laughed and laughed so that their teeth showed too.", "bbox": [148.2, 240.5, 419.3, 336.5], "size": 30.0}, {"role": "BODY", "text": "“I’ll n eve r lose", "bbox": [722.8, 126.1, 975.2, 179.2], "size": 41.1}, {"role": "BODY", "text": "my laugh again,”", "bbox": [703.2, 218.0, 993.1, 273.0], "size": 41.1}, {"role": "BODY", "text": "said Spotty the", "bbox": [717.4, 310.6, 980.4, 364.3], "size": 41.1}, {"role": "BODY", "text": "happy Hyena.", "bbox": [727.3, 403.1, 969.0, 455.6], "size": 41.3}]$$),
    ('the-lost-laugh', 12, $$$$, $$[]$$),
    ('the-lost-laugh', 13, $$$$, $$[]$$),
    ('the-memory-tree', 0, $$Thembi and Thulani like to visit the park with Grandpa Nathi. They love their Grandpa Nathi.$$, $$[{"role": "BODY", "text": "Thembi and Thulani like to visit the park with Grandpa Nathi.", "bbox": [119.3, 242.8, 447.6, 286.8], "size": 20.0}, {"role": "BODY", "text": "They love their Grandpa Nathi.", "bbox": [138.8, 314.8, 428.1, 334.8], "size": 20.0}]$$),
    ('the-memory-tree', 1, $$Beep Beep Beep But Grandpa Nathi is very sick in the hospital. His eyes are closed. The machine next to Grandpa Nathi goes beep, beep, beep. “Mommy, why won’t Grandpa Nathi sing with me?” asks Thembi. Mommy says, “Grandpa Nathi can still hear you. His heart is singing with you.”$$, $$[{"role": "BODY", "text": "Beep Beep Beep", "bbox": [38.7, 56.9, 163.4, 174.5], "size": 28.2}, {"role": "BODY", "text": "But Grandpa Nathi is very sick in the hospital. His eyes are closed.", "bbox": [678.9, 158.8, 1021.9, 202.8], "size": 20.0}, {"role": "BODY", "text": "The machine next to Grandpa Nathi goes beep, beep, beep.", "bbox": [681.5, 230.8, 1019.3, 274.8], "size": 20.0}, {"role": "BODY", "text": "“Mommy, why won’t Grandpa Nathi sing with me?” asks Thembi.", "bbox": [682.8, 302.8, 1018.0, 346.8], "size": 20.0}, {"role": "BODY", "text": "Mommy says, “Grandpa Nathi can still hear you. His heart is singing with you.”", "bbox": [665.5, 374.8, 1035.3, 418.8], "size": 20.0}]$$),
    ('the-memory-tree', 2, $$At home, Thembi and Thulani are waiting at the window. Mommy and Daddy are taking so long at the hospital. Then Thembi sees Mommy and Daddy walk up the driveway. “They are back!”$$, $$[{"role": "BODY", "text": "At home, Thembi and Thulani are waiting at the window.", "bbox": [145.1, 170.8, 421.9, 214.8], "size": 20.0}, {"role": "BODY", "text": "Mommy and Daddy are taking so long at the hospital.", "bbox": [138.8, 242.8, 428.1, 286.8], "size": 20.0}, {"role": "BODY", "text": "Then Thembi sees Mommy and Daddy walk up the driveway.", "bbox": [136.1, 314.8, 430.8, 358.8], "size": 20.0}, {"role": "BODY", "text": "“They are back!”", "bbox": [205.3, 386.8, 361.7, 406.8], "size": 20.0}]$$),
    ('the-memory-tree', 3, $$Mommy and Daddy are very sad. “What’s wrong?” asks Thembi. Her tummy feels sore. Mommy’s voice is very quiet. “Grandpa Nathi was old and sick. The doctors couldn’t make him better.” Her eyes fill with tears, “we won’t be seeing Grandpa Nathi again.”$$, $$[{"role": "BODY", "text": "Mommy and Daddy are very sad.", "bbox": [692.5, 146.8, 1008.3, 166.8], "size": 20.0}, {"role": "BODY", "text": "“What’s wrong?” asks Thembi.", "bbox": [708.0, 194.8, 992.8, 214.8], "size": 20.0}, {"role": "BODY", "text": "Her tummy feels sore.", "bbox": [746.1, 242.8, 954.7, 262.8], "size": 20.0}, {"role": "BODY", "text": "Mommy’s voice is very quiet. “Grandpa Nathi was old and sick. The doctors couldn’t make him better.”", "bbox": [667.2, 290.8, 1033.6, 358.8], "size": 20.0}, {"role": "BODY", "text": "Her eyes fill with tears, “we won’t be seeing Grandpa Nathi again.”", "bbox": [679.5, 386.8, 1021.3, 430.8], "size": 20.0}]$$),
    ('the-memory-tree', 4, $$Thulani is sitting outside under Grandpa Nathi’s favourite tree. He doesn’t feel like playing with Thembi. He wishes Grandpa Nathi could read him a story.$$, $$[{"role": "BODY", "text": "Thulani is sitting outside under Grandpa Nathi’s favourite tree.", "bbox": [136.9, 218.8, 430.1, 262.8], "size": 20.0}, {"role": "BODY", "text": "He doesn’t feel like playing with Thembi. He wishes Grandpa Nathi could read him a story.", "bbox": [124.4, 290.8, 442.5, 358.8], "size": 20.0}]$$),
    ('the-memory-tree', 5, $$Thembi is angry and throws her doll. “Why did Grandpa Nathi have to die!” Mommy pulls Thembi close on her lap. “It’s okay to be angry,” says Mommy. “I miss Grandpa Nathi, too.”$$, $$[{"role": "BODY", "text": "Thembi is angry and throws her doll. “Why did Grandpa Nathi have to die!”", "bbox": [674.0, 206.8, 1026.8, 250.8], "size": 20.0}, {"role": "BODY", "text": "Mommy pulls Thembi close on her lap.", "bbox": [669.7, 278.8, 1031.1, 298.8], "size": 20.0}, {"role": "BODY", "text": "“It’s okay to be angry,” says Mommy. “I miss Grandpa Nathi, too.”", "bbox": [674.4, 326.8, 1026.4, 370.8], "size": 20.0}]$$),
    ('the-memory-tree', 6, $$Today Mommy, Daddy, Thulani and Thembi are wearing their best clothes to go to church for Grandpa Nathi’s funeral. Everyone is coming to remember Grandpa.$$, $$[{"role": "BODY", "text": "Today Mommy, Daddy, Thulani and Thembi are wearing their best clothes to go to church for Grandpa Nathi’s funeral.", "bbox": [78.0, 230.8, 488.9, 298.8], "size": 20.0}, {"role": "BODY", "text": "Everyone is coming to remember Grandpa.", "bbox": [80.5, 326.8, 486.4, 346.8], "size": 20.0}]$$),
    ('the-memory-tree', 7, $$Mommy holds Thembi’s hand as they sing Grandpa Nathi’s favourite songs. Everybody sings and dances too.$$, $$[{"role": "BODY", "text": "Mommy holds Thembi’s hand as they sing Grandpa Nathi’s favourite songs.", "bbox": [673.3, 242.8, 1027.5, 286.8], "size": 20.0}, {"role": "BODY", "text": "Everybody sings and dances too.", "bbox": [694.7, 314.8, 1006.1, 334.8], "size": 20.0}]$$),
    ('the-memory-tree', 8, $$Thembi can’t sleep. She calls out to Mommy. “Mommy, I miss Grandpa. My heart is so sore!”$$, $$[{"role": "BODY", "text": "Thembi can’t sleep. She calls out to Mommy.", "bbox": [74.0, 254.8, 492.9, 274.8], "size": 20.0}, {"role": "BODY", "text": "“Mommy, I miss Grandpa. My heart is so sore!”", "bbox": [64.8, 302.8, 502.1, 322.8], "size": 20.0}]$$),
    ('the-memory-tree', 9, $$Thembi and Thulani are eating breakfast when Daddy walks in with a big, big, big cardboard tree. “This is a memory tree,” says Daddy. He sticks the cardboard tree on the wall. Mommy has a box of photos. “Take your favourite pictures of Grandpa Nathi and stick them on the tree.”$$, $$[{"role": "BODY", "text": "Thembi and Thulani are eating breakfast when Daddy walks in with a big, big, big cardboard tree.", "bbox": [679.9, 170.8, 1020.9, 238.8], "size": 20.0}, {"role": "BODY", "text": "“This is a memory tree,” says Daddy. He sticks the cardboard tree on the wall.", "bbox": [659.5, 266.8, 1041.3, 310.8], "size": 20.0}, {"role": "BODY", "text": "Mommy has a box of photos. “Take your favourite pictures of Grandpa Nathi and stick them on the tree.”", "bbox": [659.9, 338.8, 1040.9, 406.8], "size": 20.0}]$$),
    ('the-memory-tree', 10, $$Together they all stick pictures of Grandpa Nathi onto the tree. They remember the fun times they had. Thembi claps excitedly. “This is my new favourite tree!”$$, $$[{"role": "BODY", "text": "Together they all stick pictures of Grandpa Nathi onto the tree. They remember the fun times they had.", "bbox": [108.4, 218.8, 458.5, 286.8], "size": 20.0}, {"role": "BODY", "text": "Thembi claps excitedly. “This is my new favourite tree!”", "bbox": [136.7, 314.8, 430.2, 358.8], "size": 20.0}]$$),
    ('the-memory-tree', 11, $$Daddy smiles. “Now anytime we want to remember Grandpa Nathi, we can come to our memory tree.” “We will never forget Grandpa Nathi. He will always be in our hearts.”$$, $$[{"role": "BODY", "text": "Daddy smiles. “Now anytime we want to remember Grandpa Nathi, we can come to our memory tree.”", "bbox": [686.0, 218.8, 1014.8, 286.8], "size": 20.0}, {"role": "BODY", "text": "“We will never forget Grandpa Nathi. He will always be in our hearts.”", "bbox": [677.2, 314.8, 1023.6, 358.8], "size": 20.0}]$$),
    ('the-memory-tree', 12, $$$$, $$[]$$),
    ('the-memory-tree', 13, $$$$, $$[]$$),
    ('the-monster-must-go', 0, $$There is a MONSTER in our house.$$, $$[{"role": "BODY", "text": "There is a MONSTER in our house.", "bbox": [847.0, 381.4, 1077.2, 518.2], "size": 39.0}]$$),
    ('the-monster-must-go', 1, $$It wasn’t ALWAYS here.$$, $$[{"role": "BODY", "text": "It wasn’t ALWAYS here.", "bbox": [662.3, 151.0, 1038.5, 187.0], "size": 36.0}]$$),
    ('the-monster-must-go', 2, $$One day, it just TURNED UP.$$, $$[{"role": "BODY", "text": "One day, it just TURNED UP.", "bbox": [726.2, 375.2, 974.6, 454.4], "size": 36.0}]$$),
    ('the-monster-must-go', 3, $$Themonster EATS and ROARS all day all night.$$, $$[{"role": "BODY", "text": "Themonster EATS", "bbox": [117.9, 54.5, 455.1, 154.3], "size": 50.2}, {"role": "BODY", "text": "and ROARS", "bbox": [724.9, 47.2, 980.4, 127.7], "size": 49.4}, {"role": "BODY", "text": "all day", "bbox": [226.3, 476.1, 340.6, 518.4], "size": 39.4}, {"role": "BODY", "text": "all night.", "bbox": [783.0, 472.2, 923.6, 518.4], "size": 39.7}]$$),
    ('the-monster-must-go', 4, $$The monster is... NOIS DIRTYYY GRUMP DROOLYY SMELL STICKY$$, $$[{"role": "BODY", "text": "The monster is...", "bbox": [151.1, 180.1, 415.9, 216.1], "size": 36.0}, {"role": "BODY", "text": "NOIS DIRTYYY GRUMP DROOLYY SMELL STICKY", "bbox": [601.2, 91.6, 851.9, 407.8], "size": 38.0}]$$),
    ('the-monster-must-go', 5, $$The monster must GO!$$, $$[{"role": "SFX", "text": "The monster must GO!", "bbox": [668.5, 163.2, 1032.2, 278.7], "size": 50.4}]$$),
    ('the-monster-must-go', 6, $$Itried SCARING itof. But the LAUGHED. monster just HA-HA! HA-HA!$$, $$[{"role": "BODY", "text": "Itried SCARING itof.", "bbox": [107.5, 36.0, 503.0, 196.3], "size": 43.3}, {"role": "BODY", "text": "But the LAUGHED. monster just HA-HA! HA-HA!", "bbox": [682.2, 62.9, 1018.6, 351.1], "size": 40.5}]$$),
    ('the-monster-must-go', 7, $$Itried TRAPPINGit. Butthe monsterwas tooCUNNING .$$, $$[{"role": "BODY", "text": "Itried TRAPPINGit.", "bbox": [128.4, 56.1, 452.9, 147.1], "size": 42.5}, {"role": "BODY", "text": "Butthe monsterwas", "bbox": [677.9, 56.2, 1023.1, 156.3], "size": 43.6}, {"role": "BODY", "text": "tooCUNNING .", "bbox": [889.3, 347.0, 1072.7, 513.6], "size": 32.5}]$$),
    ('the-monster-must-go', 8, $$I even tried sending it to the MOON. But that just made it ANGRY.$$, $$[{"role": "BODY", "text": "I even tried sending it to the MOON.", "bbox": [105.9, 211.0, 461.0, 290.2], "size": 36.0}, {"role": "BODY", "text": "But that just made it ANGRY.", "bbox": [681.3, 64.7, 1019.5, 143.8], "size": 36.0}]$$),
    ('the-monster-must-go', 9, $$It’sTOO LATE! The monster’sGOTME!$$, $$[{"role": "SFX", "text": "It’sTOO LATE!", "bbox": [707.7, 105.3, 982.5, 213.9], "size": 57.4}, {"role": "BODY", "text": "The monster’sGOTME!", "bbox": [747.7, 349.8, 1071.4, 518.8], "size": 43.3}]$$),
    ('the-monster-must-go', 10, $$OOHH!!$$, $$[{"role": "SFX", "text": "OOHH!!", "bbox": [220.7, 182.4, 346.3, 254.4], "size": 72.0}]$$),
    ('the-monster-must-go', 11, $$Well... Maybe the monster isn’t SO bad.$$, $$[{"role": "BODY", "text": "Well... Maybe the monster isn’t SO bad.", "bbox": [687.8, 204.8, 1013.0, 327.2], "size": 36.0}]$$),
    ('the-monster-must-go', 12, $$$$, $$[]$$),
    ('the-monster-must-go', 13, $$$$, $$[]$$),
    ('the-new-road', 0, $$Chapansi and her best friend Luano love collecting inswa.$$, $$[{"role": "BODY", "text": "Chapansi and her best friend Luano love collecting inswa.", "bbox": [96.9, 365.0, 470.0, 426.6], "size": 28.0}]$$),
    ('the-new-road', 1, $$They love to play on the old dirt road... ....even if Mama would tsk-tsk because the stones hurt her feet.$$, $$[{"role": "BODY", "text": "They love to play on the old dirt road...", "bbox": [109.6, 62.7, 420.4, 124.3], "size": 28.0}, {"role": "BODY", "text": "....even if Mama would tsk-tsk because the stones hurt her feet.", "bbox": [739.3, 412.6, 1082.5, 507.8], "size": 28.0}]$$),
    ('the-new-road', 2, $$One day, big cars arrive. Mama calls them Caterpillars.$$, $$[{"role": "BODY", "text": "One day, big cars arrive.", "bbox": [156.9, 67.9, 470.5, 95.9], "size": 28.0}, {"role": "BODY", "text": "Mama calls them Caterpillars.", "bbox": [123.0, 423.6, 504.4, 451.6], "size": 28.0}]$$),
    ('the-new-road', 3, $$They cover the road in black stuff. Mama calls it tar.$$, $$[{"role": "BODY", "text": "They cover the road in black stuff.", "bbox": [632.5, 181.0, 1071.1, 209.0], "size": 28.0}, {"role": "BODY", "text": "Mama calls it tar.", "bbox": [743.1, 248.2, 960.5, 276.2], "size": 28.0}]$$),
    ('the-new-road', 4, $$The road is smooth now. Like walking on a mattress!$$, $$[{"role": "BODY", "text": "The road is smooth now.", "bbox": [94.8, 62.7, 409.8, 90.7], "size": 28.0}, {"role": "BODY", "text": "Like walking on a mattress!", "bbox": [673.1, 488.3, 1021.8, 516.3], "size": 28.0}]$$),
    ('the-new-road', 5, $$But when Chapansi and Luano go to the road to catch inswa... ... they only catch three!$$, $$[{"role": "BODY", "text": "But when Chapansi and Luano go to the road to catch inswa...", "bbox": [66.2, 454.7, 500.7, 516.3], "size": 28.0}, {"role": "BODY", "text": "... they only catch three!", "bbox": [700.4, 488.3, 1000.4, 516.3], "size": 28.0}]$$),
    ('the-new-road', 6, $$Chapansi used to love playing chiyato with Luano. But there are no more stones on the road to play with.$$, $$[{"role": "BODY", "text": "Chapansi used to love playing chiyato with Luano.", "bbox": [107.3, 62.7, 459.7, 124.3], "size": 28.0}, {"role": "BODY", "text": "But there are no more stones on the road to play with.", "bbox": [662.4, 458.2, 1038.4, 519.8], "size": 28.0}]$$),
    ('the-new-road', 7, $$Chapansi is worried. What if the inswa can’t breathe anymore?$$, $$[{"role": "BODY", "text": "Chapansi is worried.", "bbox": [721.8, 62.7, 979.0, 90.7], "size": 28.0}, {"role": "BODY", "text": "What if the inswa can’t breathe anymore?", "bbox": [702.8, 393.4, 995.2, 455.0], "size": 28.0}]$$),
    ('the-new-road', 8, $$Chapansi kicks the road!$$, $$[{"role": "SFX", "text": "Chapansi kicks the road!", "bbox": [703.7, 347.0, 997.1, 441.6], "size": 43.0}]$$),
    ('the-new-road', 9, $$Chapansi goes to Mama. ‘Don’t be sad, my child. Inswa will always find a way out,’ she says.$$, $$[{"role": "BODY", "text": "Chapansi goes to Mama.", "bbox": [124.2, 62.9, 442.8, 90.9], "size": 28.0}, {"role": "BODY", "text": "‘Don’t be sad, my child. Inswa will always find a way out,’ she says.", "bbox": [638.3, 272.9, 1062.5, 334.5], "size": 28.0}]$$),
    ('the-new-road', 10, $$One rainy day, Luano comes running to Chapansi’s house. ‘Inswa is back!’$$, $$[{"role": "BODY", "text": "One rainy day, Luano comes running to Chapansi’s house.", "bbox": [98.7, 102.8, 468.2, 164.4], "size": 28.0}, {"role": "SFX", "text": "‘Inswa is back!’", "bbox": [689.4, 67.1, 1011.4, 115.1], "size": 48.0}]$$),
    ('the-new-road', 11, $$Inswa is back! It defeated the road! Mama was right after all!$$, $$[{"role": "BODY", "text": "Inswa is back! It defeated the road!", "bbox": [59.8, 62.7, 507.1, 90.7], "size": 28.0}, {"role": "BODY", "text": "Mama was right after all!", "bbox": [689.8, 488.3, 1011.0, 516.3], "size": 28.0}]$$),
    ('the-new-road', 12, $$$$, $$[]$$),
    ('the-new-road', 13, $$$$, $$[]$$),
    ('the-one-in-the-middle', 0, $$I am the middle one. Not the first born. Not the last born. The one in the middle!$$, $$[{"role": "BODY", "text": "I am the middle one. Not the first born. Not the last born.", "bbox": [113.4, 214.9, 324.5, 300.9], "size": 24.0}, {"role": "BODY", "text": "The one in the middle!", "bbox": [113.4, 338.9, 344.3, 362.9], "size": 24.0}]$$),
    ('the-one-in-the-middle', 1, $$The one in the middle can be easy to forget.$$, $$[{"role": "BODY", "text": "The one in the middle can be easy to forget.", "bbox": [657.6, 132.2, 881.0, 187.2], "size": 24.0}]$$),
    ('the-one-in-the-middle', 2, $$And easy to leave out.$$, $$[{"role": "BODY", "text": "And easy to leave out.", "bbox": [737.8, 155.1, 963.0, 179.1], "size": 24.0}]$$),
    ('the-one-in-the-middle', 3, $$But that’s okay because I am also the one with IDEAS!$$, $$[{"role": "BODY", "text": "But that’s okay because I am also the one with IDEAS!", "bbox": [256.5, 245.9, 459.3, 331.9], "size": 24.0}]$$),
    ('the-one-in-the-middle', 4, $$Look what I can make from just this cardboard box! A BEAUTIFUL house… with real doors and windows.$$, $$[{"role": "BODY", "text": "Look what I can make from just this cardboard box!", "bbox": [795.0, 184.7, 993.7, 270.7], "size": 24.0}, {"role": "BODY", "text": "A BEAUTIFUL house… with real doors and windows.", "bbox": [782.0, 308.7, 1006.7, 394.7], "size": 24.0}]$$),
    ('the-one-in-the-middle', 5, $$$$, $$[]$$),
    ('the-one-in-the-middle', 6, $$My house has an extra special bed, and a MAGIC SLIDE.$$, $$[{"role": "BODY", "text": "My house has an extra special bed, and a MAGIC SLIDE.", "bbox": [750.4, 231.8, 950.4, 317.8], "size": 24.0}]$$),
    ('the-one-in-the-middle', 7, $$Some days my house is also a shop.$$, $$[{"role": "BODY", "text": "Some days my house is also a shop.", "bbox": [708.7, 261.4, 924.9, 316.4], "size": 24.0}]$$),
    ('the-one-in-the-middle', 8, $$And on other days it’s a VERY FANTASTIC show.$$, $$[{"role": "BODY", "text": "And on other days it’s a VERY FANTASTIC show.", "bbox": [141.7, 261.4, 381.4, 316.4], "size": 24.0}]$$),
    ('the-one-in-the-middle', 9, $$Sometimes my house is just for me!$$, $$[{"role": "BODY", "text": "Sometimes my house is just for me!", "bbox": [708.7, 261.4, 929.0, 316.4], "size": 24.0}]$$),
    ('the-one-in-the-middle', 10, $$And sometimes it’s a house for three! I am the middle one. Not the first born. Not the last born. The one in the middle! And that’s the best place for me.$$, $$[{"role": "BODY", "text": "And sometimes it’s a house for three!", "bbox": [79.4, 183.9, 460.5, 207.9], "size": 24.0}, {"role": "BODY", "text": "I am the middle one. Not the first born. Not the last born.", "bbox": [79.4, 245.9, 290.5, 331.9], "size": 24.0}, {"role": "BODY", "text": "The one in the middle!", "bbox": [79.4, 369.9, 310.3, 393.9], "size": 24.0}, {"role": "BODY", "text": "And that’s the best place for me.", "bbox": [684.5, 452.7, 1016.3, 476.7], "size": 24.0}]$$),
    ('the-one-in-the-middle', 11, $$$$, $$[]$$),
    ('the-one-in-the-middle', 12, $$$$, $$[]$$),
    ('the-one-in-the-middle', 13, $$$$, $$[]$$),
    ('the-pumpkin-chase', 0, $$Miss Sunflower is crying. “A thief just stole my pumpkin pie! Now what will I have for dinner?” she sobs.$$, $$[{"role": "BODY", "text": "Miss Sunflower is crying. “A thief just stole my pumpkin pie! Now what will I have for dinner?” she sobs.", "bbox": [62.9, 255.2, 504.2, 341.2], "size": 22.0}]$$),
    ('the-pumpkin-chase', 1, $$“Don’t cry Miss Sunflower. We will find your pumpkin pie,” said Officer Zig. “We will catch that crook!” said Officer Zag.$$, $$[{"role": "BODY", "text": "“Don’t cry Miss Sunflower. We will find your pumpkin pie,” said Officer Zig. “We will catch that crook!” said Officer Zag.", "bbox": [626.0, 255.2, 1075.0, 341.2], "size": 22.0}]$$),
    ('the-pumpkin-chase', 2, $$“Look! There he goes!” said Officer Zig. “Catch that crook!” said Officer Zag.$$, $$[{"role": "BODY", "text": "“Look! There he goes!” said Officer Zig.", "bbox": [84.3, 287.2, 482.8, 309.2], "size": 22.0}, {"role": "BODY", "text": "“Catch that crook!” said Officer Zag.", "bbox": [671.0, 467.3, 919.3, 521.3], "size": 22.0}]$$),
    ('the-pumpkin-chase', 3, $$“I’m too fast and you’re too slow. You will never catch the pumpkin pie thief!” cried the crook.$$, $$[{"role": "BODY", "text": "“I’m too fast and you’re too slow. You will never catch the pumpkin pie thief!” cried the crook.", "bbox": [628.0, 255.2, 1072.9, 341.2], "size": 22.0}]$$),
    ('the-pumpkin-chase', 4, $$They chased hi m up the hill... …but the crook was too quick. “I’m too fast and you’re too slow. You will never catch the pumpkin pie thief!”$$, $$[{"role": "BODY", "text": "They chased hi m up the hill...", "bbox": [102.8, 367.2, 471.8, 426.1], "size": 22.7}, {"role": "BODY", "text": "…but the crook was too quick.", "bbox": [772.8, 404.6, 1077.3, 426.6], "size": 22.0}, {"role": "BODY", "text": "“I’m too fast and you’re too slow. You will never catch the pumpkin pie thief!”", "bbox": [632.5, 468.6, 1077.4, 522.6], "size": 22.0}]$$),
    ('the-pumpkin-chase', 5, $$They chased him down the riverbank but the crook rolled away. “I’m too fast and you’re too slow. You will never catch the pumpkin pie thief!”$$, $$[{"role": "BODY", "text": "They chased him down the riverbank but the crook rolled away.", "bbox": [66.0, 428.8, 343.8, 522.6], "size": 22.0}, {"role": "BODY", "text": "“I’m too fast and you’re too slow. You will never catch the pumpkin pie thief!”", "bbox": [714.4, 63.2, 997.9, 149.2], "size": 22.0}]$$),
    ('the-pumpkin-chase', 6, $$They chased him under the bridge but the crook swam away. “I’m too fast and you’re too slow. You will never catch the pumpkin pie thief!”$$, $$[{"role": "BODY", "text": "They chased him under the bridge but the crook swam away.", "bbox": [87.0, 88.0, 479.9, 149.9], "size": 22.0}, {"role": "BODY", "text": "“I’m too fast and you’re too slow. You will never catch the pumpkin pie thief!”", "bbox": [623.3, 96.6, 829.6, 214.6], "size": 22.0}]$$),
    ('the-pumpkin-chase', 7, $$They chased him over the fires... …but the crook jumped too high. “I’m too fast and you’re too slow. You will never catch the pumpkin pie thief!”$$, $$[{"role": "BODY", "text": "They chased him over the fires...", "bbox": [99.9, 88.0, 467.1, 128.0], "size": 22.0}, {"role": "BODY", "text": "…but the crook jumped too high.", "bbox": [745.8, 209.9, 1075.7, 231.9], "size": 22.0}, {"role": "BODY", "text": "“I’m too fast and you’re too slow. You will never catch the pumpkin pie thief!”", "bbox": [759.5, 273.9, 1061.9, 359.9], "size": 22.0}]$$),
    ('the-pumpkin-chase', 8, $$They chased him around the tree but they could not catch the crook. “I’m too fast and you’re too slow. You will never catch the pumpkin pie thief!”$$, $$[{"role": "BODY", "text": "They chased him around the tree but they could not catch the crook.", "bbox": [86.7, 88.0, 480.3, 149.9], "size": 22.0}, {"role": "BODY", "text": "“I’m too fast and you’re too slow. You will never catch the pumpkin pie thief!”", "bbox": [628.0, 95.9, 1072.9, 149.9], "size": 22.0}]$$),
    ('the-pumpkin-chase', 9, $$Officer Zig and Officer Zag did not give up. They ran and ran and ran until… SPLAT! They chased him right into a wall!$$, $$[{"role": "BODY", "text": "Officer Zig and Officer Zag did not give up. They ran and ran and ran until…", "bbox": [69.6, 372.1, 497.5, 426.1], "size": 22.0}, {"role": "BODY", "text": "SPLAT! They chased him right into a wall!", "bbox": [92.2, 460.1, 474.7, 522.0], "size": 22.0}]$$),
    ('the-pumpkin-chase', 10, $$“Hurray! We caught the crook!” said the cops.$$, $$[{"role": "BODY", "text": "“Hurray! We caught the crook!” said the cops.", "bbox": [686.9, 271.2, 1014.0, 325.2], "size": 22.0}]$$),
    ('the-pumpkin-chase', 11, $$Officer Zig and Officer Zag returned the pumpkin pie to Miss Sunflower. “Thank you very much,” said Miss Sunflower. Dinner time!$$, $$[{"role": "SFX", "text": "Officer Zig and Officer Zag returned the pumpkin pie to Miss Sunflower. “Thank you very much,” said Miss Sunflower. Dinner time!", "bbox": [83.5, 207.2, 483.6, 399.3], "size": 31.0}]$$),
    ('the-pumpkin-chase', 12, $$$$, $$[]$$),
    ('the-pumpkin-chase', 13, $$$$, $$[]$$),
    ('the-rainbow-cloud', 0, $$A long time ago in the land of the Zulu people, the King Jama ka Ndaba was very powerful, wise, fair and kind.$$, $$[{"role": "BODY", "text": "A long time ago in the land of the Zulu people, the King Jama ka Ndaba was very powerful, wise, fair and kind.", "bbox": [630.3, 250.7, 1070.8, 335.7], "size": 25.0}]$$),
    ('the-rainbow-cloud', 1, $$But he had no children and he was worried that he would not have an heir. He prayed and made offerings to the gods but nothing happened.$$, $$[{"role": "BODY", "text": "But he had no children and he was worried that he would not have an heir.", "bbox": [90.5, 205.7, 476.6, 290.7], "size": 25.0}, {"role": "BODY", "text": "He prayed and made offerings to the gods but nothing happened.", "bbox": [95.6, 325.7, 471.5, 380.7], "size": 25.0}]$$),
    ('the-rainbow-cloud', 2, $$One night while the king was asleep, a witch came in a dream. “The gods have heard your plea and the queen will bear twins. One will rule the Zulu nation and the other will have magical powers,” the witch said.$$, $$[{"role": "BODY", "text": "One night while the king was asleep, a witch came in a dream.", "bbox": [669.6, 288.1, 1045.6, 343.1], "size": 25.0}, {"role": "BODY", "text": "“The gods have heard your plea and the queen will bear twins. One will rule the Zulu nation and the other will have magical powers,” the witch said.", "bbox": [658.3, 378.1, 1056.9, 523.1], "size": 25.0}]$$),
    ('the-rainbow-cloud', 3, $$Twins Mkabayi and Mmama were born but the queen cried for Mkabayi because the rule said that the first- born twin must be offered to the gods. Seeing the queen’s sadness, the king said, “From today, when twins are born, both babies will live.” The people celebrated but not all were happy with the king’s new rule.$$, $$[{"role": "BODY", "text": "Twins Mkabayi and Mmama were born but the queen cried for Mkabayi because the rule said that the first- born twin must be offered to the gods.", "bbox": [57.3, 144.8, 509.9, 259.8], "size": 25.0}, {"role": "BODY", "text": "Seeing the queen’s sadness, the king said, “From today, when twins are born, both babies will live.”", "bbox": [67.8, 294.8, 499.3, 379.8], "size": 25.0}, {"role": "BODY", "text": "The people celebrated but not all were happy with the king’s new rule.", "bbox": [67.6, 414.8, 499.6, 469.8], "size": 25.0}]$$),
    ('the-rainbow-cloud', 4, $$The little girls grew beautifully. One day Mkabayi had a stick fight and defeated a boy who bullied children. “Go away, you cursed girl!” said the boy.$$, $$[{"role": "BODY", "text": "The little girls grew beautifully. One day Mkabayi had a stick fight and defeated a boy who bullied children.", "bbox": [623.8, 205.7, 1077.2, 290.7], "size": 25.0}, {"role": "BODY", "text": "“Go away, you cursed girl!” said the boy.", "bbox": [696.4, 325.7, 1004.6, 380.7], "size": 25.0}]$$),
    ('the-rainbow-cloud', 5, $$“Come back, Mkabayi!” Mkabayi cried and ran into the forest where the frightening ghosts, Hornhead and Longtom lived.$$, $$[{"role": "BODY", "text": "“Come back, Mkabayi!”", "bbox": [148.5, 220.7, 418.5, 245.7], "size": 25.0}, {"role": "BODY", "text": "Mkabayi cried and ran into the forest where the frightening ghosts, Hornhead and Longtom lived.", "bbox": [75.1, 280.7, 492.0, 365.7], "size": 25.0}]$$),
    ('the-rainbow-cloud', 6, $$Mmama stood in silence and closed her eyes. The magic bond between the twins led Mmama to her sister .$$, $$[{"role": "BODY", "text": "Mmama stood in silence and closed her eyes.", "bbox": [676.4, 217.7, 1024.6, 272.7], "size": 25.0}, {"role": "BODY", "text": "The magic bond between the twins led Mmama to her sister .", "bbox": [630.0, 307.7, 1071.0, 371.5], "size": 25.0}]$$),
    ('the-rainbow-cloud', 7, $$Story spread 8 “No one wants to play with me, I’m cursed!” cried Mkabayi. “I want to play with you,” Mmama said.$$, $$[{"role": "BODY", "text": "Story spread 8", "bbox": [-73.7, -110.8, 59.7, -86.8], "size": 24.0}, {"role": "BODY", "text": "“No one wants to play with me, I’m cursed!” cried Mkabayi.", "bbox": [106.3, 220.7, 467.5, 275.7], "size": 25.0}, {"role": "BODY", "text": "“I want to play with you,” Mmama said.", "bbox": [133.4, 310.7, 433.7, 365.7], "size": 25.0}]$$),
    ('the-rainbow-cloud', 8, $$“We will have a nice dinner tonight Longtom,” said Hornhead. Mkabayi picked up a stick. “You can’t kill ghosts with a stick!” Longtom laughed.$$, $$[{"role": "BODY", "text": "“We will have a nice dinner tonight Longtom,” said Hornhead.", "bbox": [647.5, 190.7, 1053.5, 245.7], "size": 25.0}, {"role": "BODY", "text": "Mkabayi picked up a stick.", "bbox": [699.3, 280.7, 1001.5, 305.7], "size": 25.0}, {"role": "BODY", "text": "“You can’t kill ghosts with a stick!” Longtom laughed.", "bbox": [648.2, 340.7, 1052.8, 395.7], "size": 25.0}]$$),
    ('the-rainbow-cloud', 9, $$“How about this?” Mmama said, raising her hand. Thunder roared and lightning struck the ghosts, while a rainbow cloud protected the girls.$$, $$[{"role": "BODY", "text": "“How about this?” Mmama said, raising her hand.", "bbox": [695.4, 225.3, 1005.5, 280.3], "size": 25.0}, {"role": "BODY", "text": "Thunder roared and lightning struck the ghosts, while a rainbow cloud protected the girls.", "bbox": [692.5, 315.3, 1008.4, 430.3], "size": 25.0}]$$),
    ('the-rainbow-cloud', 10, $$“How did you do that?” Mkabayi asked. “The way you beat that boy!” Mmama said.$$, $$[{"role": "BODY", "text": "“How did you do that?” Mkabayi asked.", "bbox": [148.4, 315.8, 418.7, 370.8], "size": 25.0}, {"role": "BODY", "text": "“The way you beat that boy!” Mmama said.", "bbox": [113.5, 405.8, 453.6, 460.8], "size": 25.0}]$$),
    ('the-rainbow-cloud', 11, $$The girls went home happy, knowing that whatever happened they could protect each other.$$, $$[{"role": "BODY", "text": "The girls went home happy, knowing that whatever happened they could protect each other.", "bbox": [684.8, 242.8, 1016.1, 357.8], "size": 25.0}]$$),
    ('the-rainbow-cloud', 12, $$$$, $$[]$$),
    ('the-rainbow-cloud', 13, $$$$, $$[]$$)
  ) AS v(slug, page_index, text, blocks)
  JOIN books b
    ON b.source_platform = 'book_dash' AND b.source_id = v.slug
ON CONFLICT (book_id, page_index) DO NOTHING;
COMMIT;

